var QUESTIONS_THEORY_1 = [
{type:"mcq",diff:"easy",en:{q:"What is the immediate first step you must take if a person is in contact with a live electrical wire?",opts:["Pull them with your bare hands","Give them water to drink","Switch off the power supply","Apply a sterile dressing"],ans:2,exp:"The severity of an electric shock depends on the current and time of contact. The very first action must always be to break the contact by switching off the power supply, removing the plug, or wrenching the cable free to ensure safety."},hi:{q:"यदि कोई व्यक्ति जीवित बिजली के तार के संपर्क में है, तो आपको सबसे पहला कदम क्या उठाना चाहिए?",opts:["उन्हें अपने नंगे हाथों से खींचें","उन्हें पीने के लिए पानी दें","बिजली की आपूर्ति बंद करें","स्टेराइल ड्रेसिंग लगाएं"],ans:2,exp:"बिजली के झटके की गंभीरता करंट और संपर्क के समय पर निर्भर करती है। सुरक्षा सुनिश्चित करने के लिए बिजली की आपूर्ति बंद करके, प्लग को हटाकर, या केबल को मुक्त करके संपर्क को तोड़ना सबसे पहला कार्य होना चाहिए।"}},
{type:"mcq",diff:"easy",en:{q:"If you cannot switch off the power, which of the following materials should you stand on to safely rescue an electric shock victim?",opts:["Wet floor","Dry wood or rubber","Metal sheet","Damp cloth"],ans:1,exp:"If the power cannot be disconnected immediately, you must insulate yourself to avoid becoming part of the circuit. Standing on dry insulating materials such as dry wood, rubber, or plastic prevents the electric current from grounding through your body."},hi:{q:"यदि आप बिजली बंद नहीं कर सकते हैं, तो बिजली के झटके के शिकार व्यक्ति को सुरक्षित रूप से बचाने के लिए आपको किस सामग्री पर खड़ा होना चाहिए?",opts:["गीला फर्श","सूखी लकड़ी या रबर","धातु की चादर","नम कपड़ा"],ans:1,exp:"यदि बिजली को तुरंत काटा नहीं जा सकता है, तो सर्किट का हिस्सा बनने से बचने के लिए आपको खुद को इंसुलेट करना होगा। सूखी लकड़ी, रबर या प्लास्टिक जैसी सूखी इन्सुलेट सामग्री पर खड़े होने से विद्युत प्रवाह आपके शरीर से होकर जमीन में नहीं जा पाता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the proper physiological positioning for an electric shock casualty who is unconscious but still breathing normally?",opts:["Sitting upright","Supine position (flat on back)","Recovery position","Prone position (face down)"],ans:2,exp:"If a casualty is unconscious but breathing, they should be placed in the recovery position. This specific lateral recumbent position keeps the airway clear, prevents the tongue from blocking the throat, and allows any fluids to drain safely."},hi:{q:"बिजली के झटके से पीड़ित व्यक्ति जो बेहोश है लेकिन सामान्य रूप से सांस ले रहा है, उसके लिए उचित शारीरिक स्थिति क्या है?",opts:["सीधा बैठना","सुपाइन स्थिति (पीठ के बल लेटना)","रिकवरी स्थिति (Recovery position)","प्रोन स्थिति (मुंह के बल लेटना)"],ans:2,exp:"यदि पीड़ित बेहोश है लेकिन सांस ले रहा है, तो उसे रिकवरी स्थिति में रखा जाना चाहिए। यह विशिष्ट स्थिति वायुमार्ग (airway) को साफ रखती है, जीभ को गले को अवरुद्ध करने से रोकती है, और किसी भी तरल पदार्थ को सुरक्षित रूप से बाहर निकलने देती है।"}},
{type:"mcq",diff:"easy",en:{q:"Which critical action is strictly prohibited when providing first aid to an unconscious electric shock victim?",opts:["Loosening clothing","Checking pulse rate","Giving anything by mouth","Covering with a blanket"],ans:2,exp:"You must never give an unconscious person anything by mouth, including water or medicine. An unconscious victim lacks the swallowing reflex, which poses a severe risk of choking or aspirating fluids directly into their lungs."},hi:{q:"बेहोश बिजली के झटके वाले पीड़ित को प्राथमिक उपचार प्रदान करते समय किस महत्वपूर्ण कार्रवाई को सख्ती से प्रतिबंधित किया गया है?",opts:["कपड़े ढीले करना","नाड़ी की दर जाँचना","मुंह से कुछ भी देना","कंबल से ढंकना"],ans:2,exp:"आपको कभी भी बेहोश व्यक्ति को मुंह से पानी या दवा सहित कुछ नहीं देना चाहिए। बेहोश व्यक्ति में निगलने की क्षमता नहीं होती है, जिससे उनके फेफड़ों में तरल पदार्थ जाने या दम घुटने का गंभीर खतरा होता है।"}},
{type:"mcq",diff:"easy",en:{q:"The fundamental 'Fire Triangle' consists of three essential elements required for a fire to burn. What are they?",opts:["Fuel, Heat, and Oxygen","Wood, Water, and Air","Fuel, Light, and Carbon Dioxide","Heat, Gas, and Friction"],ans:0,exp:"Fire is a chemical reaction that requires a specific combination of three elements to ignite and sustain burning. These elements are Fuel (combustible material), Heat (ignition temperature), and Oxygen (usually from the air)."},hi:{q:"मौलिक 'फायर ट्राइएंगल' में आग जलने के लिए आवश्यक तीन तत्व शामिल हैं। वे क्या हैं?",opts:["ईंधन, ऊष्मा और ऑक्सीजन","लकड़ी, पानी और हवा","ईंधन, प्रकाश और कार्बन डाइऑक्साइड","ऊष्मा, गैस और घर्षण"],ans:0,exp:"आग एक रासायनिक प्रतिक्रिया है जिसे प्रज्वलित करने और जलने को बनाए रखने के लिए तीन तत्वों के विशिष्ट संयोजन की आवश्यकता होती है। ये तत्व ईंधन (ज्वलनशील सामग्री), ऊष्मा (इग्निशन तापमान) और ऑक्सीजन (आमतौर पर हवा से) हैं।"}},
{type:"mcq",diff:"easy",en:{q:"According to fire classification standards, materials like wood, paper, and cloth fall under which specific class of fire?",opts:["Class A","Class B","Class C","Class D"],ans:0,exp:"Fires are classified based on the nature of the fuel. Class A fires involve ordinary combustible solid materials such as wood, paper, and cloth. These fires are most effectively extinguished by cooling them with water."},hi:{q:"अग्नि वर्गीकरण मानकों के अनुसार, लकड़ी, कागज और कपड़े जैसी सामग्री आग के किस विशिष्ट वर्ग के अंतर्गत आती है?",opts:["क्लास ए (Class A)","क्लास बी (Class B)","क्लास सी (Class C)","क्लास डी (Class D)"],ans:0,exp:"आग को ईंधन की प्रकृति के आधार पर वर्गीकृत किया जाता है। क्लास ए की आग में साधारण ज्वलनशील ठोस सामग्री जैसे लकड़ी, कागज और कपड़ा शामिल होते हैं। पानी से ठंडा करके इन्हें सबसे प्रभावी ढंग से बुझाया जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"Flammable liquids and liquefiable solids, such as grease, oil, and gasoline, are categorized as which class of fire?",opts:["Class A","Class B","Class C","Class D"],ans:1,exp:"Class B fires involve flammable liquids and liquefiable solids like gasoline, oil, and grease. These fires must be smothered using foam, dry powder, or CO2 to cut off the oxygen supply; water should never be used."},hi:{q:"ज्वलनशील तरल पदार्थ और द्रवीकरण योग्य ठोस, जैसे ग्रीस, तेल और गैसोलीन को आग के किस वर्ग के रूप में वर्गीकृत किया गया है?",opts:["क्लास ए (Class A)","क्लास बी (Class B)","क्लास सी (Class C)","क्लास डी (Class D)"],ans:1,exp:"क्लास बी आग में ज्वलनशील तरल पदार्थ और द्रवीकरण योग्य ठोस जैसे गैसोलीन, तेल और ग्रीस शामिल होते हैं। ऑक्सीजन की आपूर्ति को कम करने के लिए इन आग को फोम, सूखे पाउडर या CO2 का उपयोग करके बुझाना चाहिए; पानी का उपयोग कभी नहीं करना चाहिए।"}},
{type:"mcq",diff:"easy",en:{q:"Which class of fire involves liquefied gases and poses a severe risk of explosion?",opts:["Class A","Class B","Class C","Class D"],ans:2,exp:"Class C fires involve gases and liquefied gases. These fires require extreme caution due to the high risk of explosion and sudden outbreak. Dry powder extinguishers are typically used, but shutting off the gas supply is the safest initial step."},hi:{q:"किस वर्ग की आग में तरलीकृत गैसें शामिल होती हैं और विस्फोट का गंभीर खतरा होता है?",opts:["क्लास ए (Class A)","क्लास बी (Class B)","क्लास सी (Class C)","क्लास डी (Class D)"],ans:2,exp:"क्लास सी आग में गैसें और तरलीकृत गैसें शामिल हैं। विस्फोट और अचानक भड़कने के उच्च जोखिम के कारण इन आग में अत्यधिक सावधानी की आवश्यकता होती है। आमतौर पर ड्राई पाउडर का उपयोग किया जाता है, लेकिन गैस की आपूर्ति बंद करना सबसे सुरक्षित प्रारंभिक कदम है।"}},
{type:"mcq",diff:"easy",en:{q:"Combustible metals and live electrical equipment typically require specific extinguishing agents. Which class of fire represents metals?",opts:["Class A","Class B","Class C","Class D"],ans:3,exp:"Class D fires involve combustible metals. The standard range of fire extinguishing agents is inadequate and often dangerous for metal fires. Special powders have been developed specifically to control and extinguish high-temperature Class D fires safely."},hi:{q:"ज्वलनशील धातुओं और लाइव विद्युत उपकरणों को आमतौर पर विशिष्ट बुझाने वाले एजेंटों की आवश्यकता होती है। धातुओं का प्रतिनिधित्व आग का कौन सा वर्ग करता है?",opts:["क्लास ए (Class A)","क्लास बी (Class B)","क्लास सी (Class C)","क्लास डी (Class D)"],ans:3,exp:"क्लास डी आग में ज्वलनशील धातुएं शामिल होती हैं। मानक अग्निशामक एजेंट अपर्याप्त होते हैं और अक्सर धातु की आग के लिए खतरनाक होते हैं। उच्च तापमान वाली क्लास डी आग को सुरक्षित रूप से बुझाने के लिए विशेष पाउडर विकसित किए गए हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Cooling a fire is primarily achieved by using which universal extinguishing agent to lower the combustion temperature?",opts:["Carbon Dioxide","Dry Sand","Water","Halon"],ans:2,exp:"Cooling removes the 'Heat' element from the fire triangle. Water is the most effective and universal cooling agent for Class A fires; it rapidly absorbs thermal energy, lowering the fuel's temperature below its specific ignition point."},hi:{q:"दहन तापमान को कम करने के लिए मुख्य रूप से किस सार्वभौमिक बुझाने वाले एजेंट का उपयोग करके आग को ठंडा (Cooling) किया जाता है?",opts:["कार्बन डाइऑक्साइड","सूखी रेत","पानी (Water)","हैलोन (Halon)"],ans:2,exp:"शीतलन (Cooling) आग के त्रिकोण से 'ऊष्मा' तत्व को हटा देता है। क्लास ए की आग के लिए पानी सबसे प्रभावी और सार्वभौमिक शीतलन एजेंट है; यह तेजी से थर्मल ऊर्जा को अवशोषित करता है, ईंधन के तापमान को इसके इग्निशन बिंदु से नीचे लाता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which specific method of fire extinction strictly focuses on isolating the fire from its oxygen supply using blankets or foam?",opts:["Starving","Cooling","Smothering","Ventilating"],ans:2,exp:"Smothering is the tactical method of extinguishing a fire by cutting off its oxygen supply. Blanketing the fire with foam, dry sand, or a physical fire blanket prevents atmospheric oxygen from interacting with the combustible fuel."},hi:{q:"आग बुझाने की कौन सी विशिष्ट विधि कंबलों या फोम का उपयोग करके आग को उसकी ऑक्सीजन आपूर्ति से अलग करने पर सख्ती से ध्यान केंद्रित करती है?",opts:["स्टार्विंग (Starving)","कूलिंग (Cooling)","स्मदरिंग (Smothering)","वेंटिलेटिंग (Ventilating)"],ans:2,exp:"स्मदरिंग (Smothering) ऑक्सीजन की आपूर्ति को काटकर आग बुझाने की सामरिक विधि है। आग को फोम, सूखी रेत या भौतिक आग के कंबल से ढकने से वायुमंडलीय ऑक्सीजन ज्वलनशील ईंधन के साथ संपर्क करने से रुक जाती है।"}},
{type:"mcq",diff:"easy",en:{q:"Which fire extinguisher type is absolutely prohibited from being used on Class B (flammable liquid) fires?",opts:["Foam","Carbon Dioxide (CO2)","Dry Powder","Water"],ans:3,exp:"Water must never be used on Class B fires. Flammable liquids like oil and petrol are lighter than water; applying water will cause the burning liquid to splash and spread rapidly, significantly worsening the fire hazard."},hi:{q:"क्लास बी (ज्वलनशील तरल) की आग पर किस प्रकार के अग्निशामक यंत्र का उपयोग पूर्णतः वर्जित है?",opts:["फोम","कार्बन डाइऑक्साइड (CO2)","ड्राई पाउडर","पानी (Water)"],ans:3,exp:"पानी का उपयोग क्लास बी की आग पर कभी नहीं किया जाना चाहिए। तेल और पेट्रोल जैसे ज्वलनशील तरल पदार्थ पानी से हल्के होते हैं; पानी डालने से जलता हुआ तरल छलक कर तेजी से फैलेगा, जिससे आग का खतरा काफी बढ़ जाएगा।"}},
{type:"mcq",diff:"easy",en:{q:"If an appliance fed directly from a pressurized gas cylinder catches fire, what is the absolute safest initial course of action?",opts:["Spray it with water","Cover it with a fire blanket","Shut off the gas supply","Run outside immediately"],ans:2,exp:"For Class C fires involving an appliance fed from a gas cylinder, there is an extreme risk of explosion. The safest initial technical course of action is to completely shut off the main gas supply to remove the continuous fuel source."},hi:{q:"यदि दबाव वाले गैस सिलेंडर से सीधे खिलाए गए उपकरण में आग लग जाती है, तो सबसे सुरक्षित प्रारंभिक कार्रवाई क्या है?",opts:["उस पर पानी छिड़कें","इसे आग के कंबल से ढक दें","गैस की आपूर्ति बंद करें","तुरंत बाहर भागें"],ans:2,exp:"गैस सिलेंडर से खिलाए गए उपकरण से जुड़ी क्लास सी की आग के लिए, विस्फोट का अत्यधिक जोखिम होता है। सबसे सुरक्षित प्रारंभिक तकनीकी कार्रवाई निरंतर ईंधन स्रोत को हटाने के लिए मुख्य गैस आपूर्ति को पूरी तरह से बंद करना है।"}},
{type:"mcq",diff:"easy",en:{q:"Why must you absolutely avoid using liquid or foam-based extinguishers on active electrical equipment?",opts:["They cause the equipment to rust","They are electrically conductive and pose a severe shock hazard","They evaporate too quickly","They permanently damage the circuit boards"],ans:1,exp:"Liquid (like water) and foam extinguishers are strictly prohibited for electrical fires because they are highly electrically conductive. Using them forms a conductive path to the operator, posing an immediate and fatal risk of electric shock."},hi:{q:"सक्रिय विद्युत उपकरणों पर आपको तरल या फोम-आधारित अग्निशामक यंत्रों का उपयोग करने से क्यों बचना चाहिए?",opts:["वे उपकरण में जंग का कारण बनते हैं","वे विद्युत प्रवाहकीय हैं और गंभीर झटके का खतरा पैदा करते हैं","वे बहुत जल्दी वाष्पित हो जाते हैं","वे सर्किट बोर्डों को स्थायी रूप से नुकसान पहुंचाते हैं"],ans:1,exp:"विद्युत आग के लिए तरल (जैसे पानी) और फोम बुझाने वाले यंत्र सख्त वर्जित हैं क्योंकि वे अत्यधिक विद्युत प्रवाहकीय होते हैं। उनका उपयोग करने से ऑपरेटर तक एक प्रवाहकीय मार्ग बन जाता है, जिससे बिजली के झटके का तत्काल और घातक जोखिम होता है।"}},
{type:"mcq",diff:"easy",en:{q:"What does the letter 'P' signify in the widely recognized P.A.S.S. method for operating a fire extinguisher?",opts:["Press the handle","Point the nozzle","Pull the safety pin","Push the button"],ans:2,exp:"In the P.A.S.S. acronym, 'P' stands for 'Pull the safety pin'. This pin is located at the top of the fire extinguisher handle and must be forcibly removed to unlock the operating lever before the agent can be discharged."},hi:{q:"अग्निशामक यंत्र के संचालन के लिए व्यापक रूप से मान्यता प्राप्त P.A.S.S. विधि में अक्षर 'P' क्या दर्शाता है?",opts:["हैंडल दबाएं (Press the handle)","नोजल को इंगित करें (Point the nozzle)","सेफ्टी पिन खींचें (Pull the safety pin)","बटन दबाएं (Push the button)"],ans:2,exp:"P.A.S.S. विधि में, 'P' का अर्थ 'सेफ्टी पिन खींचें' (Pull the safety pin) है। यह पिन अग्निशामक हैंडल के शीर्ष पर स्थित होता है और एजेंट को डिस्चार्ज करने से पहले ऑपरेटिंग लीवर को अनलॉक करने के लिए इसे हटाया जाना चाहिए।"}},
{type:"mcq",diff:"easy",en:{q:"In the P.A.S.S. fire extinguisher operation technique, what action does the letter 'A' direct the user to perform?",opts:["Aim at the base of the fire","Approach the fire rapidly","Activate the alarm","Assess the wind direction"],ans:0,exp:"The 'A' in P.A.S.S. stands for 'Aim the extinguisher nozzle or hose at the base of the fire'. Aiming at the base directly targets the fuel source, which is structurally necessary to break the fire triangle and suppress the flames."},hi:{q:"P.A.S.S. अग्निशामक संचालन तकनीक में, अक्षर 'A' उपयोगकर्ता को क्या कार्रवाई करने का निर्देश देता है?",opts:["आग के आधार पर निशाना लगाएँ (Aim at the base)","आग के पास तेजी से जाएं","अलार्म सक्रिय करें","हवा की दिशा का आकलन करें"],ans:0,exp:"P.A.S.S. में 'A' का अर्थ है 'अग्निशामक नोजल या नली को आग के आधार (base) पर लक्षित करें'। आधार पर निशाना लगाना सीधे ईंधन स्रोत को लक्षित करता है, जो आग के त्रिकोण को तोड़ने और लपटों को दबाने के लिए आवश्यक है।"}},
{type:"mcq",diff:"easy",en:{q:"When operating an extinguisher, what does the first 'S' (Squeeze) step in the P.A.S.S. protocol fundamentally accomplish?",opts:["It physically discharges the extinguishing agent","It aims the nozzle","It sweeps the area","It releases the safety pin"],ans:0,exp:"In the P.A.S.S. protocol, squeezing the handle lever slowly mechanically opens the valve, which allows the pressurized extinguishing agent to be discharged smoothly from the nozzle or hose onto the fire."},hi:{q:"अग्निशामक यंत्र का संचालन करते समय, P.A.S.S. प्रोटोकॉल में 'स्क्वीज़' (Squeeze) चरण मौलिक रूप से क्या पूरा करता है?",opts:["यह भौतिक रूप से बुझाने वाले एजेंट को डिस्चार्ज करता है","यह नोजल को लक्षित करता है","यह क्षेत्र को साफ करता है","यह सेफ्टी पिन जारी करता है"],ans:0,exp:"P.A.S.S. प्रोटोकॉल में, हैंडल लीवर को धीरे-धीरे निचोड़ने (squeezing) से वाल्व यंत्रवत् खुल जाता है, जिससे दबाव युक्त बुझाने वाला एजेंट नोजल या नली से आग पर सुचारू रूप से डिस्चार्ज हो जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"To extinguish a fire using the sweeping method, at what approximate distance should you sweep the nozzle from side to side over the fuel?",opts:["50 cm","100 cm","15 cm","5 cm"],ans:2,exp:"The final step of the PASS method instructs the user to sweep the nozzle from side to side approximately 15 cm over the burning fuel fire. This sweeping motion effectively blankets the entire surface of the base fuel."},hi:{q:"स्वीपिंग (sweeping) विधि का उपयोग करके आग बुझाने के लिए, आपको ईंधन के ऊपर नोजल को एक तरफ से दूसरी तरफ लगभग कितनी दूरी पर घुमाना चाहिए?",opts:["50 सेमी","100 सेमी","15 सेमी (15 cm)","5 सेमी"],ans:2,exp:"PASS विधि का अंतिम चरण उपयोगकर्ता को जलते हुए ईंधन की आग पर लगभग 15 सेमी तक नोजल को एक तरफ से दूसरी तरफ घुमाने (sweep) का निर्देश देता है। यह व्यापक गति प्रभावी रूप से बेस ईंधन की पूरी सतह को कवर करती है।"}},
{type:"mcq",diff:"easy",en:{q:"The process of intentionally starving a fire involves isolating or completely removing which specific element?",opts:["Oxygen","Heat","Fuel","Nitrogen"],ans:2,exp:"Starving is one of the three fundamental methods of fire extinction. It is strictly defined as removing or isolating the 'Fuel' element from the fire triangle, leaving the fire with nothing to actively burn."},hi:{q:"आग को जानबूझकर स्टार्व (starving) करने की प्रक्रिया में किस विशिष्ट तत्व को अलग करना या पूरी तरह से हटाना शामिल है?",opts:["ऑक्सीजन","ऊष्मा (Heat)","ईंधन (Fuel)","नाइट्रोजन"],ans:2,exp:"स्टार्विंग (Starving) आग बुझाने के तीन मूलभूत तरीकों में से एक है। इसे आग के त्रिकोण से 'ईंधन' तत्व को हटाने या अलग करने के रूप में कड़ाई से परिभाषित किया गया है, जिससे आग के पास जलने के लिए कुछ नहीं बचता।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following physical features is the primary distinguishing characteristic of a Dry Powder fire extinguisher?",opts:["A distinctive horn shape","A fork-shaped nozzle","A red colored hose","A specialized pressure gauge"],ans:1,exp:"While physically resembling water-filled extinguishers in appearance and operation, the main distinguishing mechanical feature of a Dry Powder extinguisher is its specialized fork-shaped nozzle designed for optimal powder dispersion."},hi:{q:"निम्नलिखित में से कौन सी भौतिक विशेषता ड्राई पाउडर (Dry Powder) अग्निशामक यंत्र की प्राथमिक विशिष्ट विशेषता है?",opts:["एक विशिष्ट हॉर्न का आकार","एक कांटा के आकार का नोजल (Fork-shaped nozzle)","लाल रंग की नली","एक विशेष दबाव गेज"],ans:1,exp:"जबकि देखने और संचालन में पानी से भरे अग्निशामक यंत्रों के समान, एक ड्राई पाउडर अग्निशामक की मुख्य विशिष्ट यांत्रिक विशेषता इसका विशेष कांटा के आकार का नोजल (fork-shaped nozzle) है जो इष्टतम पाउडर फैलाव के लिए डिज़ाइन किया गया है।"}},
{type:"mcq",diff:"easy",en:{q:"A Carbon Dioxide (CO2) fire extinguisher is easily identified by which highly distinct external physical component?",opts:["Fork-shaped nozzle","Long rubber hose","Distinctively shaped discharge horn","Large pressure gauge"],ans:2,exp:"Carbon Dioxide (CO2) fire extinguishers are instantly recognizable by their distinctively shaped hard plastic discharge horn. This horn safely directs the expanding, freezing CO2 gas without causing frostbite to the operator's hands."},hi:{q:"कार्बन डाइऑक्साइड (CO2) अग्निशामक यंत्र को किस अत्यधिक विशिष्ट बाहरी भौतिक घटक द्वारा आसानी से पहचाना जाता है?",opts:["कांटा के आकार का नोजल","लंबी रबर की नली","विशिष्ट आकार का डिस्चार्ज हॉर्न (Discharge horn)","बड़ा दबाव गेज"],ans:2,exp:"कार्बन डाइऑक्साइड (CO2) अग्निशामक यंत्रों को उनके विशिष्ट आकार के हार्ड प्लास्टिक डिस्चार्ज हॉर्न द्वारा तुरंत पहचाना जा सकता है। यह हॉर्न ऑपरेटर के हाथों को फ्रॉस्टबाइट (जमने) के बिना विस्तारित, ठंडे CO2 गैस को सुरक्षित रूप से निर्देशित करता है।"}},
{type:"mcq",diff:"easy",en:{q:"During an emergency fire evacuation procedure, where should all personnel safely gather after leaving the premises calmly?",opts:["Inside the server room","At the designated assembly point","In the nearest corridor","Near the electrical panel"],ans:1,exp:"The standard safety procedure dictates that anyone not involved in active firefighting must evacuate calmly using emergency exits and report directly to the designated assembly point to ensure every person is correctly accounted for."},hi:{q:"आपातकालीन अग्नि निकासी प्रक्रिया के दौरान, परिसर को शांति से छोड़ने के बाद सभी कर्मियों को सुरक्षित रूप से कहाँ इकट्ठा होना चाहिए?",opts:["सर्वर कक्ष के अंदर","नामित असेंबली पॉइंट पर (Designated assembly point)","निकटतम गलियारे में","विद्युत पैनल के पास"],ans:1,exp:"मानक सुरक्षा प्रक्रिया यह निर्देश देती है कि जो कोई भी सक्रिय अग्निशमन में शामिल नहीं है, उसे आपातकालीन निकास का उपयोग करके शांति से बाहर निकलना चाहिए और सीधे नामित असेंबली पॉइंट पर रिपोर्ट करना चाहिए ताकि हर व्यक्ति की सही गिनती हो सके।"}},
{type:"mcq",diff:"easy",en:{q:"What is the initial logical step when you unexpectedly discover a fire outbreak in your working environment?",opts:["Open all windows","Raise an alarm","Run away silently","Start recording a video"],ans:1,exp:"The absolute first step in the general procedure upon discovering a fire is to raise an alarm. Alerting surrounding people by shouting 'fire' or activating the fire alarm ensures rapid evacuation and immediate notification to fire services."},hi:{q:"जब आप अपने काम के माहौल में अप्रत्याशित रूप से आग लगने का पता लगाते हैं तो प्रारंभिक तार्किक कदम क्या होता है?",opts:["सभी खिड़कियां खोलें","अलार्म बजाएं (Raise an alarm)","चुपचाप भाग जाओ","वीडियो रिकॉर्ड करना शुरू करें"],ans:1,exp:"आग का पता चलने पर सामान्य प्रक्रिया में सबसे पहला कदम अलार्म बजाना है। 'आग' चिल्लाकर आसपास के लोगों को सचेत करना या फायर अलार्म को सक्रिय करना तेजी से निकासी और अग्निशमन सेवाओं को तत्काल अधिसूचना सुनिश्चित करता है।"}},
{type:"mcq",diff:"easy",en:{q:"When combating a fire, which physiological action helps the operator avoid inhaling toxic fumes and superheated air?",opts:["Running constantly","Keeping yourself low","Standing on a chair","Breathing rapidly"],ans:1,exp:"When fighting a fire, the operator is explicitly instructed to 'keep yourself low'. Heat, toxic smoke, and dangerous fumes naturally rise, so staying close to the ground ensures access to cooler, breathable air and better visibility."},hi:{q:"आग से लड़ते समय, कौन सी शारीरिक क्रिया ऑपरेटर को जहरीले धुएं और अत्यधिक गर्म हवा में सांस लेने से बचने में मदद करती है?",opts:["लगातार दौड़ना","खुद को नीचे रखना (Keeping yourself low)","कुर्सी पर खड़ा होना","तेजी से सांस लेना"],ans:1,exp:"आग से लड़ते समय, ऑपरेटर को स्पष्ट रूप से 'खुद को नीचे रखने' का निर्देश दिया जाता है। गर्मी, जहरीला धुआं और खतरनाक धुएं स्वाभाविक रूप से ऊपर उठते हैं, इसलिए जमीन के करीब रहने से ठंडी, सांस लेने योग्य हवा और बेहतर दृश्यता सुनिश्चित होती है।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following is considered a major fire risk related to combustible refuse?",opts:["Keeping cotton waste soaked with oil in odd corners","Storing empty metal bins","Using LED lights","Properly stacking dry wood in a safe zone"],ans:0,exp:"The accumulation of combustible refuse, specifically items like cotton waste soaked with oil or scrap paper in odd corners, poses a severe spontaneous combustion and fire risk. Such refuse must be removed to designated collection points."},hi:{q:"निम्नलिखित में से किसे ज्वलनशील कचरे से संबंधित प्रमुख अग्नि जोखिम माना जाता है?",opts:["विषम कोनों में तेल से लथपथ सूती कचरा रखना","खाली धातु के डिब्बे का भंडारण","एलईडी लाइट का उपयोग करना","सूखी लकड़ी को सुरक्षित क्षेत्र में ठीक से जमा करना"],ans:0,exp:"ज्वलनशील कचरे का संचय, विशेष रूप से विषम कोनों में तेल या रद्दी कागज से लथपथ सूती कचरा, सहज दहन और आग का गंभीर जोखिम पैदा करता है। ऐसे कचरे को निर्दिष्ट संग्रह बिंदुओं पर हटा दिया जाना चाहिए।"}},
{type:"mcq",diff:"easy",en:{q:"What specifically happens if you fail to close doors and windows during a fire outbreak?",opts:["It traps the smoke inside","It feeds oxygen to the fire and helps it spread","It prevents people from escaping","It increases the room temperature instantly"],ans:1,exp:"Closing doors and windows (without locking them) limits the natural oxygen supply fed to the fire. Leaving them open allows fresh air drafts to oxygenate the flames, encouraging the fire to grow and spread rapidly across rooms."},hi:{q:"यदि आप आग लगने के दौरान दरवाजे और खिड़कियां बंद करने में विफल रहते हैं तो विशेष रूप से क्या होता है?",opts:["यह धुएं को अंदर फंसाता है","यह आग को ऑक्सीजन देता है और इसे फैलने में मदद करता है","यह लोगों को भागने से रोकता है","यह कमरे का तापमान तुरंत बढ़ा देता है"],ans:1,exp:"दरवाजे और खिड़कियां बंद करने (बिना लॉक किए) से आग को मिलने वाली प्राकृतिक ऑक्सीजन की आपूर्ति सीमित हो जाती है। उन्हें खुला छोड़ने से ताजी हवा लपटों को ऑक्सीजन देती है, जिससे आग बढ़ती है और कमरों में तेजी से फैलती है।"}},
{type:"tf",diff:"easy",en:{q:"It is completely safe and acceptable practice to use standard water-filled extinguishers to successfully control a running liquid fuel fire.",opts:["True","False"],ans:1,exp:"This is false. Water must never be used on liquid fuel fires (Class B). Because most flammable liquids are less dense than water, they will float on top of the water, causing the burning fuel to spread dangerously instead of extinguishing."},hi:{q:"बहते हुए तरल ईंधन (liquid fuel) की आग को सफलतापूर्वक नियंत्रित करने के लिए मानक पानी से भरे अग्निशामक यंत्रों का उपयोग करना पूरी तरह से सुरक्षित और स्वीकार्य अभ्यास है।",opts:["सही","गलत"],ans:1,exp:"यह गलत है। तरल ईंधन की आग (क्लास बी) पर पानी का उपयोग कभी नहीं किया जाना चाहिए। चूँकि अधिकांश ज्वलनशील तरल पदार्थ पानी से कम घने होते हैं, वे पानी के ऊपर तैरेंगे, जिससे बुझने के बजाय जलता हुआ ईंधन खतरनाक रूप से फैल जाएगा।"}},
{type:"tf",diff:"easy",en:{q:"Foam extinguishers operate primarily through the scientific principle of smothering, structurally blanketing the liquid surface to completely cut off the supply of atmospheric oxygen.",opts:["True","False"],ans:0,exp:"This is true. The fundamental aim of a foam extinguisher on Class B fires is to create a physical, cohesive blanket across the entire surface of the burning liquid, mechanically isolating the fuel from atmospheric oxygen (smothering)."},hi:{q:"फोम बुझाने वाले यंत्र मुख्य रूप से स्मदरिंग (smothering) के वैज्ञानिक सिद्धांत के माध्यम से काम करते हैं, जो वायुमंडलीय ऑक्सीजन की आपूर्ति को पूरी तरह से काटने के लिए तरल सतह को संरचनात्मक रूप से ढकते हैं।",opts:["सही","गलत"],ans:0,exp:"यह सत्य है। क्लास बी आग पर फोम बुझाने वाले का मूल उद्देश्य जलते हुए तरल की पूरी सतह पर एक भौतिक कंबल बनाना है, जो यंत्रवत् वायुमंडलीय ऑक्सीजन (स्मदरिंग) से ईंधन को अलग करता है।"}},
{type:"mcq",diff:"medium",en:{q:"If a victim is suffering an electric shock while elevated aloft, what critical secondary safety measure must the rescuer take before breaking the circuit?",opts:["Ensure the power line is fully grounded","Take measures to prevent a dangerous physical fall","Spray the victim with a cooling agent","Administer artificial respiration immediately"],ans:1,exp:"When a victim is shocked while aloft (e.g., on a ladder or pole), muscles can freeze. Breaking the contact will cause them to release instantly. The rescuer must take proactive measures to prevent severe secondary trauma from a catastrophic fall."},hi:{q:"यदि कोई पीड़ित ऊंचाई (aloft) पर बिजली के झटके का सामना कर रहा है, तो सर्किट तोड़ने से पहले बचावकर्ता को कौन सा महत्वपूर्ण द्वितीयक सुरक्षा उपाय करना चाहिए?",opts:["सुनिश्चित करें कि पावर लाइन पूरी तरह से ग्राउंडेड है","खतरनाक शारीरिक गिरावट (गिरने) को रोकने के उपाय करें","पीड़ित पर कूलिंग एजेंट का छिड़काव करें","तुरंत कृत्रिम श्वसन कराएं"],ans:1,exp:"जब किसी पीड़ित को ऊंचाई पर झटका लगता है, तो मांसपेशियां जम सकती हैं। संपर्क तोड़ने से वे तुरंत छूट जाएंगे। बचावकर्ता को विनाशकारी गिरावट से गंभीर द्वितीयक आघात (चोट) को रोकने के लिए सक्रिय उपाय करने चाहिए।"}},
{type:"mcq",diff:"medium",en:{q:"What is the defining physiological characteristic of deep-seated electric burns, and how should they be initially treated by a first aider?",opts:["They cover a massive surface area; apply ice packs","They are often localized but deep; cover with a clean sterile dressing","They bleed profusely; apply a tight tourniquet","They are superficial; wash aggressively with soap"],ans:1,exp:"Electric burns differ from thermal burns; they may not visibly cover a large surface area but are often structurally deep-seated, damaging underlying tissue. They must be carefully covered with a clean, sterile dressing while treating the patient for overall shock."},hi:{q:"गहरे बैठे बिजली के जलने (deep-seated electric burns) की परिभाषित शारीरिक विशेषता क्या है, और प्राथमिक उपचारकर्ता द्वारा उनका प्रारंभिक इलाज कैसे किया जाना चाहिए?",opts:["वे एक बड़े सतह क्षेत्र को कवर करते हैं; आइस पैक लगाएं","वे अक्सर स्थानीयकृत लेकिन गहरे होते हैं; एक साफ स्टेराइल ड्रेसिंग के साथ कवर करें","वे प्रचुर मात्रा में खून बहाते हैं; एक तंग टूर्निकेट लागू करें","वे सतही हैं; साबुन से आक्रामक रूप से धोएं"],ans:1,exp:"बिजली के जलने थर्मल जलने से भिन्न होते हैं; वे एक बड़े सतह क्षेत्र को कवर नहीं कर सकते हैं लेकिन अक्सर गहरे बैठे होते हैं, जो अंतर्निहित ऊतकों को नुकसान पहुंचाते हैं। समग्र झटके के लिए रोगी का इलाज करते समय उन्हें सावधानीपूर्वक एक साफ, स्टेराइल ड्रेसिंग के साथ कवर किया जाना चाहिए।"}},
{type:"mcq",diff:"medium",en:{q:"What specific underlying electrical malfunction is frequently cited as a primary technical cause for equipment overheating and subsequent electrical fires?",opts:["Using oversized copper cabling","Applying correctly rated heavy-duty fuses","Loose connections and wrongly rated fuses","Operating on direct current (DC) systems"],ans:2,exp:"The primary cause of electrical fires is generally misuse or systemic neglect. Specifically, structural issues like loose terminal connections, overloaded circuits, and wrongly rated fuses generate excessive localized resistance and overheating, leading directly to ignition."},hi:{q:"उपकरण के अति ताप (overheating) और बाद में बिजली की आग के लिए प्राथमिक तकनीकी कारण के रूप में किस विशिष्ट अंतर्निहित विद्युत खराबी का अक्सर हवाला दिया जाता है?",opts:["बड़े आकार के तांबे के केबल का उपयोग करना","सही रेटिंग वाले हेवी-ड्यूटी फ़्यूज़ लगाना","ढीले कनेक्शन और गलत रेटिंग वाले फ़्यूज़ (Loose connections and wrongly rated fuses)","प्रत्यक्ष धारा (DC) प्रणालियों पर काम करना"],ans:2,exp:"विद्युत आग का प्राथमिक कारण आम तौर पर दुरुपयोग या उपेक्षा है। विशेष रूप से, ढीले टर्मिनल कनेक्शन, अतिभारित (overloaded) सर्किट और गलत रेटिंग वाले फ़्यूज़ अत्यधिक स्थानीय प्रतिरोध और गर्मी पैदा करते हैं, जिससे आग लग जाती है।"}},
{type:"mcq",diff:"medium",en:{q:"Regarding physical evaporation properties, why is liquid petrol considered highly dangerous even at a normal room temperature of 15°C?",opts:["It spontaneously combusts without an ignition source","It naturally gives off highly flammable vapor at normal room temperatures","It chemically reacts violently with ambient atmospheric nitrogen","It freezes, expanding and breaking storage containers"],ans:1,exp:"Unlike solid fuels that require significant heating, specific liquids like petrol do not have to be heated to become dangerous. They naturally give off highly flammable vapor at normal ambient room temperatures (say 15°C), which readily ignites."},hi:{q:"भौतिक वाष्पीकरण गुणों के संबंध में, तरल पेट्रोल को 15°C के सामान्य कमरे के तापमान पर भी अत्यधिक खतरनाक क्यों माना जाता है?",opts:["यह प्रज्वलन स्रोत के बिना स्वतः दहन करता है","यह स्वाभाविक रूप से सामान्य कमरे के तापमान पर अत्यधिक ज्वलनशील वाष्प (vapor) छोड़ता है","यह परिवेश वायुमंडलीय नाइट्रोजन के साथ हिंसक रूप से रासायनिक प्रतिक्रिया करता है","यह जम जाता है, जिससे भंडारण कंटेनर टूट जाते हैं"],ans:1,exp:"ठोस ईंधन के विपरीत जिन्हें महत्वपूर्ण हीटिंग की आवश्यकता होती है, पेट्रोल जैसे विशिष्ट तरल पदार्थों को खतरनाक होने के लिए गर्म नहीं किया जाना चाहिए। वे स्वाभाविक रूप से सामान्य कमरे के तापमान (मान लें 15°C) पर अत्यधिक ज्वलनशील वाष्प छोड़ते हैं, जो आसानी से प्रज्वलित हो जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which highly effective extinguishing agent is fundamentally recommended for Class B running liquid fires, operating safely on electrically non-conductive principles?",opts:["Pressurized Water jets","Halon (Vapourising liquid) extinguishers","Aqueous Film Forming Foam (AFFF)","Conductive Dry Sand"],ans:1,exp:"Halon extinguishers (filled with Carbon-tetrachloride or BCF) are exceptionally effective in extinguishing small fires involving pouring or running liquids. Crucially, they are completely safe to use on electrical equipment because the complex chemicals are electrically non-conductive."},hi:{q:"विद्युत रूप से गैर-प्रवाहकीय सिद्धांतों पर सुरक्षित रूप से काम करते हुए, क्लास बी रनिंग लिक्विड (बहते तरल) आग के लिए मूल रूप से किस अत्यधिक प्रभावी बुझाने वाले एजेंट की सिफारिश की जाती है?",opts:["दबाव वाले पानी के जेट","हैलोन (Halon - वाष्पीकरण तरल) बुझाने वाले यंत्र","जलीय फिल्म बनाने वाला फोम (AFFF)","प्रवाहकीय सूखी रेत"],ans:1,exp:"हैलोन बुझाने वाले यंत्र (कार्बन-टेट्राक्लोराइड या BCF से भरे हुए) बहने वाले तरल पदार्थों से जुड़ी छोटी आग को बुझाने में असाधारण रूप से प्रभावी हैं। महत्वपूर्ण बात यह है कि विद्युत उपकरणों पर उपयोग करने के लिए वे पूरी तरह से सुरक्षित हैं क्योंकि रसायन गैर-प्रवाहकीय (non-conductive) होते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"Despite their superior electrical fire suppression capabilities, what represents the primary physiological danger when deploying Halon or CTC extinguishers?",opts:["They cause rapid localized frostbite on human skin","They emit dangerous, highly toxic fumes, especially in confined workspaces","They aggressively corrode all exposed copper wiring","They produce a blinding, physically opaque white powder cloud"],ans:1,exp:"While Halon and Carbon-tetrachloride (CTC) extinguishers are excellent for electrical and pouring liquid fires, the complex chemical fumes they give off during discharge are extremely dangerous and toxic, specifically when deployed in enclosed, poorly ventilated spaces."},hi:{q:"अपनी बेहतर विद्युत अग्नि शमन क्षमताओं के बावजूद, हैलोन (Halon) या CTC बुझाने वाले यंत्रों को तैनात करते समय प्राथमिक शारीरिक खतरा क्या है?",opts:["वे मानव त्वचा पर तेजी से स्थानीयकृत शीतदंश (frostbite) का कारण बनते हैं","वे खतरनाक, अत्यधिक विषैले धुएं छोड़ते हैं, खासकर सीमित कार्यक्षेत्रों में","वे आक्रामक रूप से सभी खुले तांबे के तारों को खराब कर देते हैं","वे एक अंधा करने वाला, भौतिक रूप से अपारदर्शी सफेद पाउडर बादल उत्पन्न करते हैं"],ans:1,exp:"जबकि हैलोन और कार्बन-टेट्राक्लोराइड (CTC) अग्निशामक विद्युत और तरल आग के लिए उत्कृष्ट हैं, निर्वहन के दौरान वे जो रासायनिक धुएं छोड़ते हैं वे बेहद खतरनाक और विषैले होते हैं, विशेष रूप से बंद, खराब हवादार स्थानों (confined space) में।"}},
{type:"mcq",diff:"medium",en:{q:"Why is the instruction given to 'not lock or bolt' doors and windows during an emergency fire evacuation?",opts:["To allow massive amounts of oxygen to naturally enter the building","To let the internal heat safely escape into the atmosphere","To prevent active firefighters and evacuating personnel from getting physically trapped","To structurally increase the internal draft speed for smoke clearance"],ans:2,exp:"During a fire, standard procedure dictates closing doors to limit oxygen supply, but strictly prohibits locking or bolting them. Locking doors poses a catastrophic risk of trapping evacuees inside and severely delaying rescue efforts by firefighters."},hi:{q:"आपातकालीन अग्नि निकासी के दौरान दरवाजे और खिड़कियों को 'लॉक या बोल्ट नहीं करने' का निर्देश क्यों दिया जाता है?",opts:["इमारत में स्वाभाविक रूप से भारी मात्रा में ऑक्सीजन प्रवेश करने देने के लिए","आंतरिक गर्मी को सुरक्षित रूप से वायुमंडल में भागने देने के लिए","सक्रिय अग्निशामकों और निकासी कर्मियों को शारीरिक रूप से फंसने से रोकने के लिए","धुएं की निकासी के लिए संरचनात्मक रूप से आंतरिक ड्राफ्ट गति बढ़ाने के लिए"],ans:2,exp:"आग के दौरान, मानक प्रक्रिया ऑक्सीजन की आपूर्ति को सीमित करने के लिए दरवाजे बंद करने का निर्देश देती है, लेकिन उन्हें लॉक या बोल्ट करने से सख्ती से रोकती है। दरवाजों को लॉक करने से निकासी करने वालों के अंदर फंसने का विनाशकारी जोखिम होता है और बचाव प्रयासों में देरी होती है।"}},
{type:"mcq",diff:"medium",en:{q:"From a mechanical operation standpoint, how does a standard water-filled fire extinguisher typically conserve its contents during suppression?",opts:["By mechanically diluting the internal water with atmospheric air","By exclusively relying on slow gas cartridge depletion","Through a mechanism allowing the discharge to be actively interrupted as required","By rapidly freezing the internal water into slush"],ans:2,exp:"Water-filled extinguishers, whether utilizing a gas cartridge or stored pressure, possess a valve mechanism that allows the active discharge to be manually interrupted. This specific feature conserves the limited water contents and prevents unnecessary water damage to the surrounding area."},hi:{q:"यांत्रिक संचालन के दृष्टिकोण से, एक मानक पानी से भरा अग्निशामक यंत्र दमन (suppression) के दौरान अपनी सामग्री को कैसे संरक्षित करता है?",opts:["वायुमंडलीय हवा के साथ आंतरिक पानी को यंत्रवत् रूप से पतला करके","विशेष रूप से धीमी गैस कार्ट्रिज की कमी पर निर्भर होकर","एक तंत्र के माध्यम से जिससे आवश्यकतानुसार डिस्चार्ज को सक्रिय रूप से बाधित किया जा सके","आंतरिक पानी को तेजी से कीचड़ में जमा कर"],ans:2,exp:"पानी से भरे अग्निशामक यंत्रों में एक वाल्व तंत्र होता है जो सक्रिय निर्वहन (discharge) को मैन्युअल रूप से बाधित करने की अनुमति देता है। यह विशिष्ट विशेषता सीमित पानी की सामग्री को संरक्षित करती है और आसपास के क्षेत्र में अनावश्यक पानी की क्षति को रोकती है।"}},
{type:"mcq",diff:"medium",en:{q:"In what specific directional manner should a pressurized jet of water be applied to effectively suppress an open Class A fire?",opts:["Continuously sprayed randomly from the top down","Sprayed exclusively at the very center of the flames","Sprayed systematically at the base of the fire and then gradually upwards","Directed into the rising smoke plume to cool the atmosphere"],ans:2,exp:"For optimal cooling efficiency on a Class A fire, jets of water should be directed precisely at the base of the fire (the fuel source) first. Once the base is targeted, the stream should be guided gradually upwards to systematically extinguish the flames."},hi:{q:"एक खुली क्लास ए (Class A) आग को प्रभावी ढंग से दबाने के लिए पानी के दबाव वाले जेट को किस विशिष्ट दिशात्मक तरीके से लगाया जाना चाहिए?",opts:["लगातार ऊपर से नीचे की ओर बेतरतीब ढंग से छिड़काव किया गया","विशेष रूप से लपटों के ठीक केंद्र में छिड़काव किया गया","व्यवस्थित रूप से आग के आधार (base) पर छिड़काव किया गया और फिर धीरे-धीरे ऊपर की ओर","वातावरण को ठंडा करने के लिए उठते धुएं के गुबार में निर्देशित"],ans:2,exp:"क्लास ए आग पर इष्टतम शीतलन दक्षता के लिए, पानी के जेट को पहले आग के आधार (ईंधन स्रोत) पर सटीक रूप से निर्देशित किया जाना चाहिए। एक बार आधार लक्षित हो जाने के बाद, लपटों को व्यवस्थित रूप से बुझाने के लिए धारा को धीरे-धीरे ऊपर की ओर निर्देशित किया जाना चाहिए।"}},
{type:"mcq",diff:"medium",en:{q:"Structurally, which internal component dictates the fundamental difference between the two primary variants of Foam extinguishers?",opts:["The presence of a fork-shaped discharge nozzle","The inclusion of either a gas cartridge or a stored pressure mechanism","The specific color coding of the outer cylinder","The integration of an automatic pressure relief valve"],ans:1,exp:"Foam extinguishers (and similarly water/dry powder types) mechanically come in two main operational variants based on pressurization: the 'stored pressure' type, where the entire cylinder is pressurized, and the 'gas cartridge' type, which contains a separate internal CO2 cartridge pierced upon activation."},hi:{q:"संरचनात्मक रूप से, कौन सा आंतरिक घटक फोम (Foam) बुझाने वाले यंत्रों के दो प्राथमिक प्रकारों के बीच मूलभूत अंतर को निर्धारित करता है?",opts:["कांटा के आकार का डिस्चार्ज नोजल की उपस्थिति","गैस कार्ट्रिज या संग्रहीत दबाव (stored pressure) तंत्र का समावेश","बाहरी सिलेंडर की विशिष्ट रंग कोडिंग","स्वचालित दबाव राहत वाल्व का एकीकरण"],ans:1,exp:"फोम बुझाने वाले यंत्र (और इसी तरह पानी/सूखे पाउडर प्रकार) दबाव के आधार पर दो मुख्य परिचालन प्रकारों में आते हैं: 'संग्रहीत दबाव' (stored pressure) प्रकार, जहां पूरा सिलेंडर दबाव में होता है, और 'गैस कार्ट्रिज' प्रकार, जिसमें एक अलग आंतरिक CO2 कार्ट्रिज होता है।"}},
{type:"mcq",diff:"medium",en:{q:"When executing the final 'Sweep' step in the PASS procedure, the operator is explicitly instructed to physically sweep the nozzle from side to side until:",opts:["The entire extinguisher cylinder is completely empty","The fire is completely put out","The ambient smoke clears entirely","The safety pin can be reinserted"],ans:1,exp:"The PASS procedure's final step explicitly directs the user to sweep the extinguishing agent side to side approximately 15 cm over the base fuel fire *until the fire is put off* (extinguished completely). It does not mandate blindly emptying the cylinder if unnecessary."},hi:{q:"PASS प्रक्रिया में अंतिम 'स्वीप' (Sweep) चरण को निष्पादित करते समय, ऑपरेटर को स्पष्ट रूप से नोजल को एक तरफ से दूसरी तरफ घुमाने का निर्देश दिया जाता है जब तक कि:",opts:["पूरा अग्निशामक सिलेंडर पूरी तरह से खाली हो जाए","आग पूरी तरह से बुझ जाए (fire is put off)","आसपास का धुआं पूरी तरह से साफ हो जाए","सेफ्टी पिन फिर से डाला जा सके"],ans:1,exp:"PASS प्रक्रिया का अंतिम चरण उपयोगकर्ता को बुझाने वाले एजेंट को जलते हुए ईंधन पर तब तक एक तरफ से दूसरी तरफ घुमाने का निर्देश देता है *जब तक कि आग बुझ न जाए*। यदि अनावश्यक हो तो यह आंख मूंदकर सिलेंडर को खाली करने का आदेश नहीं देता है।"}},
{type:"mcq",diff:"medium",en:{q:"What critical warning regarding situational awareness is given if a fire fails to respond well after an extinguisher has been fully discharged?",opts:["Immediately run to find another identical extinguisher","Attempt to physically smother the flames with a heavy blanket","Move away yourself immediately from the fire point","Attempt to ventilate the area by breaking windows"],ans:2,exp:"Safety protocols sternly warn that if a fire does not respond well and the extinguisher is fully depleted, the operator must immediately abandon the firefighting effort and move away from the fire point. Remaining endangers the operator's life unnecessarily."},hi:{q:"स्थिति संबंधी जागरूकता के संबंध में क्या महत्वपूर्ण चेतावनी दी जाती है यदि अग्निशामक यंत्र के पूरी तरह से खाली होने के बाद भी आग अच्छी तरह से प्रतिक्रिया करने में विफल रहती है?",opts:["तुरंत एक और समान बुझाने वाला यंत्र खोजने के लिए दौड़ें","भारी कंबल से लपटों को भौतिक रूप से बुझाने का प्रयास करें","आग लगने वाले स्थान से तुरंत खुद को दूर कर लें (Move away)","खिड़कियां तोड़कर क्षेत्र को हवादार बनाने का प्रयास करें"],ans:2,exp:"सुरक्षा प्रोटोकॉल कड़ी चेतावनी देते हैं कि यदि आग अच्छी तरह से प्रतिक्रिया नहीं करती है और बुझाने वाला यंत्र पूरी तरह से समाप्त हो गया है, तो ऑपरेटर को तुरंत अग्निशमन प्रयास को छोड़ देना चाहिए और आग के बिंदु से दूर जाना चाहिए। वहां रुकना ऑपरेटर के जीवन को अनावश्यक रूप से खतरे में डालता है।"}},
{type:"mcq",diff:"medium",en:{q:"Before physically triggering a fire extinguisher, what mandatory visual check must a trained operator routinely perform regarding the equipment itself?",opts:["Confirming the exact weight of the cylinder","Locating the nearest primary fire exit route","Checking the specific expiry date of the unit","Verifying the chemical composition of the agent"],ans:2,exp:"Before deploying a fire extinguisher, the standard protocol requires the operator to locate and pick up the correct unit, and critically, 'Check for its expiry date' to ensure the chemical agent and pressurization are still functionally viable."},hi:{q:"अग्निशामक यंत्र को भौतिक रूप से ट्रिगर करने से पहले, एक प्रशिक्षित ऑपरेटर को उपकरण के संबंध में कौन सी अनिवार्य दृश्य जाँच (visual check) नियमित रूप से करनी चाहिए?",opts:["सिलेंडर के सटीक वजन की पुष्टि करना","निकटतम प्राथमिक अग्नि निकास मार्ग का पता लगाना","यूनिट की विशिष्ट समाप्ति तिथि (expiry date) की जाँच करना","एजेंट की रासायनिक संरचना का सत्यापन करना"],ans:2,exp:"अग्निशामक यंत्र को तैनात करने से पहले, मानक प्रोटोकॉल के अनुसार ऑपरेटर को सही इकाई का पता लगाने और चुनने की आवश्यकता होती है, और सबसे महत्वपूर्ण बात, इसकी 'समाप्ति तिथि की जांच करें' ताकि यह सुनिश्चित हो सके कि यह कार्यशील है।"}},
{type:"mcq",diff:"medium",en:{q:"Which specific category of combustible material primarily necessitates the development and deployment of uniquely formulated 'Special powders' rather than standard agents?",opts:["Liquefiable solids (grease)","Ordinary combustible solids (wood)","Live highly-rated electrical equipment","Combustible metals"],ans:3,exp:"Standard agents (water, regular foam, standard CO2) are structurally inadequate and often catastrophically dangerous when applied to burning combustible metals (Class D). Therefore, uniquely formulated 'Special powders' have been exclusively developed to control and suppress these extreme-temperature metal fires."},hi:{q:"ज्वलनशील सामग्री की किस विशिष्ट श्रेणी को मुख्य रूप से मानक एजेंटों के बजाय विशिष्ट रूप से तैयार किए गए 'विशेष पाउडर' (Special powders) के विकास और तैनाती की आवश्यकता होती है?",opts:["द्रवीकरण योग्य ठोस (ग्रीस)","साधारण ज्वलनशील ठोस (लकड़ी)","लाइव उच्च श्रेणी के विद्युत उपकरण","ज्वलनशील धातुएँ (Combustible metals)"],ans:3,exp:"मानक एजेंट अपर्याप्त होते हैं और अक्सर धातु (क्लास डी) की आग पर उपयोग किए जाने पर विनाशकारी रूप से खतरनाक होते हैं। इसलिए, इन चरम-तापमान धातु की आग को नियंत्रित करने के लिए विशेष रूप से 'विशेष पाउडर' विकसित किए गए हैं।"}},
{type:"mcq",diff:"medium",en:{q:"Is there a specific designated fire classification letter strictly assigned to 'electrical fires' in the standard system?",opts:["Yes, it is classified as Class E","Yes, it is classified as Class C","No, there is no separate classification for electrical fires as such","Yes, it is grouped uniquely under Class D"],ans:2,exp:"According to standard classification texts, 'There is no classification for electrical fires as such, since these are only fires in materials where electricity is present'. The presence of electricity dictates the agent (non-conductive like CO2/Halon), but the fire itself burns the surrounding materials (plastic, copper insulation, etc.)."},hi:{q:"क्या मानक प्रणाली में 'विद्युत आग' के लिए कोई विशिष्ट अग्नि वर्गीकरण अक्षर कड़ाई से निर्दिष्ट है?",opts:["हाँ, इसे क्लास E के रूप में वर्गीकृत किया गया है","हाँ, इसे क्लास C के रूप में वर्गीकृत किया गया है","नहीं, इस प्रकार विद्युत आग के लिए कोई अलग वर्गीकरण नहीं है","हाँ, इसे विशिष्ट रूप से क्लास D के अंतर्गत समूहीकृत किया गया है"],ans:2,exp:"मानक वर्गीकरण ग्रंथों के अनुसार, 'विद्युत आग के लिए इस तरह का कोई वर्गीकरण नहीं है, क्योंकि ये केवल उन सामग्रियों में आग होती हैं जहां बिजली मौजूद होती है'। बिजली की उपस्थिति एजेंट को निर्धारित करती है, लेकिन आग आसपास की सामग्री को जलाती है।"}},
{type:"mcq",diff:"medium",en:{q:"For Class C fires involving liquefied gases, why are Dry Powder extinguishers specifically recommended after shutting off the primary gas supply?",opts:["They chemically freeze the volatile gas instantly","They safely interrupt the chemical chain reaction of the gas flame","They leave a thick, impenetrable foam layer over the gas leak","They absorb the radiant heat faster than water"],ans:1,exp:"Class C fires involve high-pressure gases. While shutting off the gas supply is paramount, if extinguishing is necessary, Dry Powder extinguishers are explicitly recommended. They safely and effectively interrupt the chemical chain reaction of the gas flame without conducting electricity or freezing the valves like CO2 might."},hi:{q:"तरलीकृत गैसों से जुड़ी क्लास सी की आग के लिए, प्राथमिक गैस आपूर्ति बंद करने के बाद विशेष रूप से ड्राई पाउडर बुझाने वाले यंत्रों की सिफारिश क्यों की जाती है?",opts:["वे अस्थिर गैस को तुरंत रासायनिक रूप से जमा देते हैं","वे गैस की लौ की रासायनिक श्रृंखला प्रतिक्रिया को सुरक्षित रूप से बाधित करते हैं","वे गैस रिसाव पर एक मोटी, अभेद्य फोम परत छोड़ते हैं","वे पानी की तुलना में तेजी से दीप्तिमान गर्मी को अवशोषित करते हैं"],ans:1,exp:"क्लास सी की आग में उच्च दबाव वाली गैसें शामिल होती हैं। जबकि गैस आपूर्ति बंद करना सर्वोपरि है, यदि बुझाना आवश्यक है, तो स्पष्ट रूप से ड्राई पाउडर की सिफारिश की जाती है। वे बिजली का संचालन किए बिना या वाल्व को जमाए बिना गैस लौ की रासायनिक श्रृंखला प्रतिक्रिया को सुरक्षित रूप से बाधित करते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"In the context of electrical fires, why must foam or liquid (e.g., water) extinguishers be strictly avoided under all circumstances?",opts:["They cause the electrical panel to rust instantly","They are highly electrically conductive and pose a fatal shock risk","They evaporate too fast to effectively cool the wiring","They chemically degrade the plastic insulation on wires"],ans:1,exp:"The text explicitly commands: 'Foam or liquid (eg. water) extinguishers must not be used on electrical equipment under any circumstances'. Because water and standard foam contain conductive elements, deploying them bridges a highly conductive path between the live voltage source and the operator, risking fatal electrocution."},hi:{q:"विद्युत आग के संदर्भ में, सभी परिस्थितियों में फोम या तरल (जैसे, पानी) बुझाने वाले यंत्रों से कड़ाई से क्यों बचा जाना चाहिए?",opts:["वे विद्युत पैनल में तुरंत जंग लगने का कारण बनते हैं","वे अत्यधिक विद्युत प्रवाहकीय (conductive) होते हैं और घातक झटके का जोखिम पैदा करते हैं","वे तारों को प्रभावी ढंग से ठंडा करने के लिए बहुत तेजी से वाष्पित हो जाते हैं","वे तारों पर प्लास्टिक इन्सुलेशन को रासायनिक रूप से नीचा दिखाते हैं"],ans:1,exp:"पाठ स्पष्ट रूप से आदेश देता है: 'किसी भी परिस्थिति में बिजली के उपकरणों पर फोम या तरल (जैसे पानी) बुझाने वाले यंत्रों का उपयोग नहीं किया जाना चाहिए'। चूँकि पानी और फोम प्रवाहकीय होते हैं, इसलिए उनका उपयोग करने से ऑपरेटर को घातक बिजली का झटका लगने का खतरा होता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which extinguishing agent is fundamentally designed for safe usage in environments where sensitive contamination by chemical deposits must be entirely avoided?",opts:["Dry Powder","Carbon Dioxide (CO2)","Foam","Water"],ans:1,exp:"Carbon Dioxide (CO2) is highly recommended for Class B fires in areas where contamination by solid chemical deposits must be strictly avoided. CO2 leaves no physical residue, making it ideal for server rooms and sensitive electronic areas."},hi:{q:"कौन सा बुझाने वाला एजेंट मूल रूप से उन वातावरणों में सुरक्षित उपयोग के लिए डिज़ाइन किया गया है जहां रासायनिक जमा द्वारा संवेदनशील संदूषण से पूरी तरह से बचा जाना चाहिए?",opts:["ड्राई पाउडर","कार्बन डाइऑक्साइड (CO2)","फोम","पानी"],ans:1,exp:"कार्बन डाइऑक्साइड (CO2) की उन क्षेत्रों में क्लास बी आग के लिए अत्यधिक अनुशंसा की जाती है जहां ठोस रासायनिक जमा द्वारा संदूषण से कड़ाई से बचा जाना चाहिए। CO2 कोई भौतिक अवशेष नहीं छोड़ता है, जो इसे इलेक्ट्रॉनिक क्षेत्रों के लिए आदर्श बनाता है।"}},
{type:"mcq",diff:"medium",en:{q:"What general safety rule applies to the usage of high-temperature tools like blowlamps and torches in a workshop?",opts:["They must be left burning at all times for easy access","They must not be left burning when they are not in active use","They should only be used near highly flammable liquids","They should be cooled with a direct water spray after every use"],ans:1,exp:"A critical common-sense fire prevention rule states that blowlamps and torches must never be left actively burning when they are not in immediate use. An unattended open flame in a workshop environment represents a massive, unpredictable fire hazard."},hi:{q:"कार्यशाला में ब्लोलैंप और टॉर्च जैसे उच्च तापमान वाले उपकरणों के उपयोग पर कौन सा सामान्य सुरक्षा नियम लागू होता है?",opts:["आसान पहुंच के लिए उन्हें हर समय जलता हुआ छोड़ दिया जाना चाहिए","जब वे सक्रिय उपयोग में न हों तो उन्हें जलता हुआ नहीं छोड़ा जाना चाहिए","उनका उपयोग केवल अत्यधिक ज्वलनशील तरल पदार्थों के पास किया जाना चाहिए","प्रत्येक उपयोग के बाद उन्हें पानी के स्प्रे से ठंडा किया जाना चाहिए"],ans:1,exp:"एक महत्वपूर्ण अग्नि निवारण नियम कहता है कि ब्लोलैंप और टॉर्च को कभी भी जलता हुआ नहीं छोड़ा जाना चाहिए जब वे तत्काल उपयोग में न हों। कार्यशाला के माहौल में लावारिस खुली लौ एक बड़े आग के खतरे का प्रतिनिधित्व करती है।"}},
{type:"mcq",diff:"medium",en:{q:"To prevent fire hazards in the workplace, what safety precaution must be taken regarding clothing and portable heaters?",opts:["Spray clothing with water before approaching a heater","Keep clothing well away from heaters and shut off heaters at day's end","Only use heaters set to the maximum temperature","Dry damp clothing directly on top of the heater grill"],ans:1,exp:"Standard fire prevention rules dictate that clothing and anything else which might easily catch fire should be kept well away from active heaters. Furthermore, you must always make sure that the heater is fully shut off at the end of the working day."},hi:{q:"कार्यस्थल पर आग के खतरों को रोकने के लिए, कपड़ों और पोर्टेबल हीटरों के संबंध में क्या सुरक्षा सावधानी बरती जानी चाहिए?",opts:["हीटर के पास जाने से पहले कपड़ों पर पानी छिड़कें","कपड़ों को हीटर से दूर रखें और दिन के अंत में हीटर बंद कर दें","केवल अधिकतम तापमान पर सेट हीटर का उपयोग करें","गीले कपड़ों को सीधे हीटर ग्रिल के ऊपर सुखाएं"],ans:1,exp:"मानक अग्नि निवारण नियम यह निर्देश देते हैं कि कपड़े और अन्य कोई भी चीज़ जिसमें आसानी से आग लग सकती है, उसे सक्रिय हीटर से दूर रखा जाना चाहिए। इसके अलावा, काम के अंत में हीटर को पूरी तरह से बंद कर देना चाहिए।"}},
{type:"mcq",diff:"medium",en:{q:"Under what specific environmental condition is a standard Foam extinguisher generally considered not effective?",opts:["In highly confined indoor spaces","In the open air where wind disperses the foam blanket","In areas containing high-voltage direct current (DC) panels","In server rooms with low ambient temperatures"],ans:1,exp:"Foam extinguishers are highly effective on Class B liquid fires by smothering them. However, the text notes they are 'not generally effective in open air'. In open environments, wind can easily break or disperse the cohesive foam blanket, re-exposing the fuel to oxygen."},hi:{q:"किस विशिष्ट पर्यावरणीय स्थिति में एक मानक फोम बुझाने वाले यंत्र को आम तौर पर अप्रभावी माना जाता है?",opts:["अत्यधिक सीमित इनडोर स्थानों में","खुली हवा में (open air) जहां हवा फोम के कंबल को तितर-बितर कर देती है","उच्च वोल्टेज प्रत्यक्ष धारा (DC) पैनल वाले क्षेत्रों में","कम परिवेश के तापमान वाले सर्वर कमरों में"],ans:1,exp:"फोम बुझाने वाले यंत्र क्लास बी तरल आग को स्मदरिंग करके बुझाने में अत्यधिक प्रभावी हैं। हालांकि, पाठ में कहा गया है कि वे 'आम तौर पर खुली हवा में प्रभावी नहीं हैं'। खुले वातावरण में, हवा आसानी से फोम के कंबल को तितर-बितर कर सकती है।"}},
{type:"mcq",diff:"medium",en:{q:"In advanced fire terminology, the specific tactical procedure of 'Starving' a fire is scientifically executed by which exact physical intervention?",opts:["Blanketing the entire combustion zone with dry sand to isolate the atmospheric oxygen","Directing high-pressure water jets to drop the thermal energy below the ignition point","Systematically isolating or physically removing the combustible fuel source from the combination","Venting the confined room to rapidly exhaust the toxic smoke plume"],ans:2,exp:"Fire extinction relies on eliminating one of the three Fire Triangle factors. 'Starving' the fire is the precise tactical method of physically removing or isolating the 'fuel' element itself, effectively denying the fire the raw material it requires to burn."},hi:{q:"उन्नत अग्नि शब्दावली में, आग को 'स्टार्विंग' (Starving) करने की विशिष्ट सामरिक प्रक्रिया वैज्ञानिक रूप से किस भौतिक हस्तक्षेप द्वारा निष्पादित की जाती है?",opts:["वायुमंडलीय ऑक्सीजन को अलग करने के लिए पूरे दहन क्षेत्र को सूखी रेत से ढंकना","इग्निशन बिंदु से नीचे थर्मल ऊर्जा को छोड़ने के लिए उच्च दबाव वाले पानी के जेट को निर्देशित करना","संयोजन से ज्वलनशील ईंधन स्रोत (fuel source) को व्यवस्थित रूप से अलग करना या भौतिक रूप से हटाना","जहरीले धुएं को तेजी से बाहर निकालने के लिए सीमित कमरे को हवा देना"],ans:2,exp:"आग बुझाना फायर ट्राइएंगल कारकों में से एक को खत्म करने पर निर्भर करता है। आग को 'स्टार्विंग' (Starving) करना 'ईंधन' तत्व को भौतिक रूप से हटाने या अलग करने की सटीक सामरिक विधि है, जो आग को जलने के लिए आवश्यक कच्चे माल से प्रभावी ढंग से वंचित करती है।"}},
{type:"mcq",diff:"medium",en:{q:"When executing the 'Smothering' tactic on a Class B flammable liquid fire, what precise physical mechanism is actively preventing the continuation of combustion?",opts:["The rapid reduction of the fuel's internal core temperature","The physical blanketing of the surface, which completely isolates the fuel from the atmospheric oxygen supply","The aggressive chemical neutralization of the liquid's hydrocarbon chains","The systematic starving of the fire by draining the liquid fuel reservoir"],ans:1,exp:"The 'Smothering' method relies on attacking the oxygen side of the fire triangle. By utilizing agents like thick foam or dry sand, the operator effectively 'blankets' the entire surface of the burning liquid, creating a physical barrier that isolates the fuel from the necessary supply of oxygen."},hi:{q:"क्लास बी ज्वलनशील तरल आग पर 'स्मदरिंग' (Smothering) रणनीति को क्रियान्वित करते समय, कौन सा सटीक भौतिक तंत्र दहन की निरंतरता को सक्रिय रूप से रोक रहा है?",opts:["ईंधन के आंतरिक कोर तापमान में तेजी से कमी","सतह का भौतिक आच्छादन, जो ईंधन को वायुमंडलीय ऑक्सीजन आपूर्ति से पूरी तरह अलग करता है (isolates the fuel)","तरल की हाइड्रोकार्बन श्रृंखलाओं का आक्रामक रासायनिक बेअसरकरण","तरल ईंधन भंडार को निकालकर आग का व्यवस्थित रूप से स्टार्विंग"],ans:1,exp:"'स्मदरिंग' विधि आग के त्रिकोण के ऑक्सीजन पक्ष पर हमला करने पर निर्भर करती है। मोटे फोम या सूखी रेत जैसे एजेंटों का उपयोग करके, ऑपरेटर प्रभावी रूप से जलते हुए तरल की पूरी सतह को 'कंबल' (blanket) की तरह ढकता है, एक भौतिक अवरोध पैदा करता है जो ईंधन को ऑक्सीजन की आवश्यक आपूर्ति से अलग करता है।"}},
{type:"mcq",diff:"medium",en:{q:"When operating an extinguisher, what does the 'Squeeze' step in the P.A.S.S. protocol fundamentally accomplish?",opts:["It physically discharges the extinguishing agent","It aims the nozzle","It sweeps the area","It releases the safety pin"],ans:0,exp:"In the P.A.S.S. protocol, squeezing the handle lever slowly mechanically opens the valve, which allows the pressurized extinguishing agent to be discharged smoothly from the nozzle or hose onto the fire."},hi:{q:"अग्निशामक यंत्र का संचालन करते समय, P.A.S.S. प्रोटोकॉल में 'स्क्वीज़' (Squeeze) चरण मौलिक रूप से क्या पूरा करता है?",opts:["यह भौतिक रूप से बुझाने वाले एजेंट को डिस्चार्ज करता है","यह नोजल को लक्षित करता है","यह क्षेत्र को साफ करता है","यह सेफ्टी पिन जारी करता है"],ans:0,exp:"P.A.S.S. प्रोटोकॉल में, हैंडल लीवर को धीरे-धीरे निचोड़ने (squeezing) से वाल्व यंत्रवत् खुल जाता है, जिससे दबाव युक्त बुझाने वाला एजेंट नोजल या नली से आग पर सुचारू रूप से डिस्चार्ज हो जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"If an operator encounters a highly volatile Class C fire originating from a localized appliance fed by a high-pressure gas cylinder, what is the absolute most critical, immediate safety instruction?",opts:["Charge aggressively with a standard water extinguisher","Attempt to systematically smother the intense flames utilizing a heavy-duty fire blanket","Immediately and completely shut off the primary supply of gas from the cylinder","Run into the enclosed room and aggressively open all primary ventilation windows"],ans:2,exp:"Class C fires involving pressurized gases represent an extreme, immediate risk of catastrophic explosion. The text explicitly directs that if an appliance fed from a cylinder catches fire, the absolute most critical action is to 'shut off the supply of gas', thereby starving the fire at its source."},hi:{q:"यदि कोई ऑपरेटर एक उच्च दबाव वाले गैस सिलेंडर द्वारा खिलाए गए एक स्थानीय उपकरण से उत्पन्न होने वाली अत्यधिक वाष्पशील क्लास सी आग का सामना करता है, तो सबसे महत्वपूर्ण, तत्काल सुरक्षा निर्देश क्या है?",opts:["मानक जल अग्निशामक यंत्र के साथ आक्रामक रूप से चार्ज करें","हेवी-ड्यूटी फायर ब्लैंकेट का उपयोग करके तीव्र लपटों को व्यवस्थित रूप से बुझाने का प्रयास करें","सिलेंडर से गैस की प्राथमिक आपूर्ति को तुरंत और पूरी तरह से बंद कर दें (shut off the supply of gas)","बंद कमरे में दौड़ें और आक्रामक रूप से सभी प्राथमिक वेंटिलेशन खिड़कियां खोलें"],ans:2,exp:"दबाव वाली गैसों से जुड़ी क्लास सी की आग विनाशकारी विस्फोट के अत्यधिक, तत्काल जोखिम का प्रतिनिधित्व करती है। यदि सिलेंडर से निकलने वाले उपकरण में आग लग जाती है, तो सबसे महत्वपूर्ण कार्रवाई 'गैस की आपूर्ति बंद करना' है, जिससे आग को उसके स्रोत पर ही रोक दिया जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"If a casualty is completely unconscious and not breathing after an electric shock, what is the crucial directive given by safety protocols?",opts:["Act at once - don't waste time, start appropriate resuscitation procedures immediately","Wait patiently for professional medical personnel to arrive before touching them","Attempt to force water down their throat to revive them","Apply a tight tourniquet to their arms to raise blood pressure"],ans:0,exp:"The strict instruction when encountering a casualty who is not breathing is: 'Act at once - don't waste time'. Delaying action leads to permanent brain damage or death. Immediate life-saving measures (like CPR) must be initiated."},hi:{q:"यदि बिजली के झटके के बाद कोई पीड़ित पूरी तरह से बेहोश है और सांस नहीं ले रहा है, तो सुरक्षा प्रोटोकॉल द्वारा दिया गया महत्वपूर्ण निर्देश क्या है?",opts:["तुरंत कार्रवाई करें - समय बर्बाद न करें, तुरंत उचित पुनर्जीवन प्रक्रियाएं शुरू करें","उन्हें छूने से पहले पेशेवर चिकित्सा कर्मियों के आने का धैर्यपूर्वक प्रतीक्षा करें","उन्हें पुनर्जीवित करने के लिए उनके गले में पानी डालने का प्रयास करें","रक्तचाप बढ़ाने के लिए उनकी बाहों पर एक कड़ा टूर्निकेट लगाएं"],ans:0,exp:"जब कोई पीड़ित सांस नहीं ले रहा हो तो सख्त निर्देश है: 'एकदम कार्य करें - समय बर्बाद न करें'। कार्रवाई में देरी से स्थायी मस्तिष्क क्षति या मृत्यु हो सकती है। तत्काल जीवन रक्षक उपाय (जैसे सीपीआर) शुरू किए जाने चाहिए।"}},
{type:"mcq",diff:"medium",en:{q:"In the P.A.S.S. fire extinguisher operation technique, what specific physical target does the letter 'A' direct the user to aim at?",opts:["The highest visible point of the flames","The absolute base of the fire where the fuel resides","The surrounding atmosphere to cool the room","The center mass of the smoke cloud"],ans:1,exp:"The 'A' in P.A.S.S. stands for 'Aim the extinguisher nozzle or hose at the base of the fire'. Aiming at the base directly targets the combustible fuel source, which is structurally necessary to break the fire triangle and suppress the flames effectively."},hi:{q:"P.A.S.S. अग्निशामक संचालन तकनीक में, अक्षर 'A' उपयोगकर्ता को किस विशिष्ट भौतिक लक्ष्य पर निशाना लगाने का निर्देश देता है?",opts:["लपटों का उच्चतम दृश्य बिंदु","आग का पूर्ण आधार (base) जहाँ ईंधन रहता है","कमरे को ठंडा करने के लिए आसपास का वातावरण","धुएं के बादल का केंद्र द्रव्यमान"],ans:1,exp:"P.A.S.S. में 'A' का अर्थ है 'अग्निशामक नोजल या नली को आग के आधार (base) पर लक्षित करें'। आधार पर निशाना लगाना सीधे ईंधन स्रोत को लक्षित करता है, जो आग के त्रिकोण को तोड़ने और लपटों को दबाने के लिए आवश्यक है।"}},
{type:"mcq",diff:"medium",en:{q:"If forced to combat an uncontrollable fire involving Class B liquids, why is the explicit use of a standard Aqueous Liquid (water) extinguisher deemed catastrophically hazardous?",opts:["It generates an impenetrable cloud of toxic steam","Water causes burning liquids to float, splash, and rapidly spread the fire","It establishes a highly conductive electrical pathway","It fails to lower the ignition temperature of heavy metals"],ans:1,exp:"Water must never be used on liquid fuel fires (Class B). Because most flammable liquids (like oil/petrol) are less dense than water, applying a pressurized water jet will cause the burning fuel to violently splash and float, spreading the hazard dangerously."},hi:{q:"यदि क्लास बी तरल पदार्थों से जुड़ी बेकाबू आग से निपटने के लिए मजबूर किया जाता है, तो मानक जलीय तरल (पानी) अग्निशामक यंत्र का स्पष्ट उपयोग विनाशकारी रूप से खतरनाक क्यों माना जाता है?",opts:["यह जहरीली भाप का एक अभेद्य बादल उत्पन्न करता है","पानी के कारण जलते हुए तरल पदार्थ तैरते हैं, छलकते हैं और आग तेजी से फैलती है","यह एक उच्च प्रवाहकीय विद्युत मार्ग स्थापित करता है","यह भारी धातुओं के इग्निशन तापमान को कम करने में विफल रहता है"],ans:1,exp:"तरल ईंधन की आग (क्लास बी) पर पानी का उपयोग कभी नहीं किया जाना चाहिए। चूँकि अधिकांश ज्वलनशील तरल पदार्थ पानी से कम घने होते हैं, इसलिए पानी डालने से जलता हुआ ईंधन तेजी से छलक कर तैरेगा, जिससे आग का खतरा काफी बढ़ जाएगा।"}},
{type:"tf",diff:"medium",en:{q:"A primary technical reason for utilizing Carbon Dioxide (CO2) extinguishers on active electrical panels is that the gas is highly electrically non-conductive and dissipates without leaving a solid residue.",opts:["True","False"],ans:0,exp:"This is true. CO2 is an excellent choice for electrical fires because it safely displaces oxygen (smothering), is intrinsically non-conductive preventing shock hazards to the user, and evaporates cleanly without depositing damaging residues on delicate circuit boards."},hi:{q:"सक्रिय विद्युत पैनलों पर कार्बन डाइऑक्साइड (CO2) बुझाने वाले यंत्रों का उपयोग करने का एक प्राथमिक तकनीकी कारण यह है कि गैस अत्यधिक विद्युत रूप से गैर-प्रवाहकीय है और एक ठोस अवशेष छोड़े बिना फैल जाती है।",opts:["सही","गलत"],ans:0,exp:"यह सत्य है। विद्युत आग के लिए CO2 एक उत्कृष्ट विकल्प है क्योंकि यह सुरक्षित रूप से ऑक्सीजन (स्मदरिंग) को विस्थापित करता है, स्वाभाविक रूप से गैर-प्रवाहकीय है, और सर्किट बोर्डों पर हानिकारक अवशेष जमा किए बिना वाष्पित हो जाता है।"}},
{type:"tf",diff:"medium",en:{q:"When rescuing a completely unconscious electric shock victim who is actively breathing, you should immediately force them to drink large quantities of water to rehydrate their system.",opts:["True","False"],ans:1,exp:"This is absolutely false. A cardinal rule of first aid states: 'Do not give an unconscious person anything by mouth.' Forcing fluids into an unconscious victim will likely bypass the stomach and enter the lungs, causing fatal aspiration or choking."},hi:{q:"पूरी तरह से बेहोश बिजली के झटके के शिकार व्यक्ति को बचाते समय जो सक्रिय रूप से सांस ले रहा है, आपको उनके सिस्टम को फिर से हाइड्रेट करने के लिए तुरंत बड़ी मात्रा में पानी पीने के लिए मजबूर करना चाहिए।",opts:["सही","गलत"],ans:1,exp:"यह बिल्कुल गलत है। प्राथमिक उपचार का एक प्रमुख नियम कहता है: 'बेहोश व्यक्ति को मुंह से कुछ भी न दें।' बेहोश पीड़ित के मुंह में तरल पदार्थ डालने से उनके फेफड़ों में पानी जाने और दम घुटने की संभावना होती है।"}},
{type:"mcq",diff:"hard",en:{q:"Within the strict context of Halon fire extinguisher chemical compositions, what does the specific acronym BCF technically stand for?",opts:["Bromochlorofluoromethane","Bromochlorodifluoro methene","Barium Calcium Fluoride","Boron Chloride Fluorocarbon"],ans:1,exp:"Halon extinguishers are specifically documented as being filled with complex vapourising liquids. The text explicitly identifies these volatile chemicals as Carbon-tetrachloride (CTC) and Bromochlorodifluoro methene, which is strictly abbreviated as BCF."},hi:{q:"हैलोन अग्निशामक रासायनिक संरचनाओं के सख्त संदर्भ में, विशिष्ट संक्षिप्त नाम BCF तकनीकी रूप से क्या दर्शाता है?",opts:["ब्रोमोक्लोरोफ्लोरोमीथेन","ब्रोमोक्लोरोडिफ्लुओरो मेथेन (Bromochlorodifluoro methene)","बेरियम कैल्शियम फ्लोराइड","बोरॉन क्लोराइड फ्लोरोकार्बन"],ans:1,exp:"हैलोन बुझाने वाले यंत्रों को विशेष रूप से जटिल वाष्पीकरण तरल पदार्थों से भरे होने के रूप में प्रलेखित किया गया है। पाठ स्पष्ट रूप से इन वाष्पशील रसायनों को कार्बन-टेट्राक्लोराइड (CTC) और ब्रोमोक्लोरोडिफ्लुओरो मेथेन (Bromochlorodifluoro methene) के रूप में पहचानता है, जिसे BCF के रूप में संक्षिप्त किया गया है।"}},
{type:"mcq",diff:"hard",en:{q:"In terms of complex chemical composition nomenclature referenced for Halon extinguishers, the specific compound Carbon-tetrachloride is often paired with which other highly toxic vapourising liquid?",opts:["Bromochlorodifluoro methene (BCF)","Sodium Bicarbonate","Potassium Chloride","Monoammonium Phosphate"],ans:0,exp:"Halon extinguishers are specifically designed around vapourising liquids. The text identifies the two primary highly volatile compounds utilized in these legacy systems as Carbon-tetrachloride (CTC) and Bromochlorodifluoro methene (which is technically abbreviated as BCF)."},hi:{q:"हैलोन बुझाने वाले यंत्रों के लिए संदर्भित जटिल रासायनिक संरचना नामकरण के संदर्भ में, विशिष्ट यौगिक कार्बन-टेट्राक्लोराइड को अक्सर किस अन्य अत्यधिक विषैले वाष्पीकरण तरल (vapourising liquid) के साथ जोड़ा जाता है?",opts:["ब्रोमोक्लोरोडिफ्लुओरो मेथेन (BCF)","सोडियम बाईकारबोनिट","पोटेशियम क्लोराइड","मोनोअमोनियम फॉस्फेट"],ans:0,exp:"हैलोन बुझाने वाले यंत्र विशेष रूप से वाष्पीकरण करने वाले तरल पदार्थों के आसपास डिज़ाइन किए गए हैं। पाठ इन प्रणालियों में उपयोग किए जाने वाले दो प्राथमिक अत्यधिक वाष्पशील यौगिकों की पहचान कार्बन-टेट्राक्लोराइड (CTC) और ब्रोमोक्लोरोडिफ्लुओरो मेथेन (Bromochlorodifluoro methene) के रूप में करता है।"}},
{type:"mcq",diff:"hard",en:{q:"In advanced fire terminology, the specific tactical procedure of 'Starving' a fire is scientifically executed by which exact physical intervention?",opts:["Blanketing the entire combustion zone with dry sand to isolate the atmospheric oxygen","Directing high-pressure water jets to drop the thermal energy below the ignition point","Systematically isolating or physically removing the combustible fuel source from the combination","Venting the confined room to rapidly exhaust the toxic smoke plume"],ans:2,exp:"Fire extinction relies on eliminating one of the three Fire Triangle factors. 'Starving' the fire is the precise tactical method of physically removing or isolating the 'fuel' element itself, effectively denying the fire the raw material it requires to burn."},hi:{q:"उन्नत अग्नि शब्दावली में, आग को 'स्टार्विंग' (Starving) करने की विशिष्ट सामरिक प्रक्रिया वैज्ञानिक रूप से किस भौतिक हस्तक्षेप द्वारा निष्पादित की जाती है?",opts:["वायुमंडलीय ऑक्सीजन को अलग करने के लिए पूरे दहन क्षेत्र को सूखी रेत से ढंकना","इग्निशन बिंदु से नीचे थर्मल ऊर्जा को छोड़ने के लिए उच्च दबाव वाले पानी के जेट को निर्देशित करना","संयोजन से ज्वलनशील ईंधन स्रोत (fuel source) को व्यवस्थित रूप से अलग करना या भौतिक रूप से हटाना","जहरीले धुएं को तेजी से बाहर निकालने के लिए सीमित कमरे को हवा देना"],ans:2,exp:"आग बुझाना फायर ट्राइएंगल कारकों में से एक को खत्म करने पर निर्भर करता है। आग को 'स्टार्विंग' (Starving) करना 'ईंधन' तत्व को भौतिक रूप से हटाने या अलग करने की सटीक सामरिक विधि है, जो आग को जलने के लिए आवश्यक कच्चे माल से प्रभावी ढंग से वंचित करती है।"}},
{type:"mcq",diff:"hard",en:{q:"When responding to an electrical shock incident where the casualty is aloft, what is the most critical hazard the rescuer must preemptively mitigate before isolating the power?",opts:["The victim receiving secondary severe burns from arching","The victim suffering catastrophic physical trauma from an uncontrolled fall","The rescuer absorbing residual static electricity from the ladder","The rapid spontaneous combustion of the victim's clothing"],ans:1,exp:"When a person receives a shock while working aloft, the electrical current often causes involuntary muscle clamping. If the power is suddenly isolated, the muscles release instantly, precipitating an uncontrolled, potentially fatal physical fall. Measures *must* be taken preemptively to prevent this secondary trauma."},hi:{q:"बिजली के झटके की घटना का जवाब देते समय जहां पीड़ित ऊंचाई (aloft) पर है, बिजली को अलग करने से पहले बचावकर्ता को किस सबसे गंभीर खतरे को कम करना चाहिए?",opts:["पीड़ित को आर्चिंग से द्वितीयक गंभीर जलन होना","पीड़ित का अनियंत्रित रूप से गिरने के कारण विनाशकारी शारीरिक आघात (चोट) सहना","सीढ़ी से अवशिष्ट स्थैतिक बिजली को अवशोषित करने वाला बचावकर्ता","पीड़ित के कपड़ों का तेजी से स्वतः दहन"],ans:1,exp:"जब किसी व्यक्ति को ऊंचाई पर काम करते समय झटका लगता है, तो विद्युत प्रवाह अक्सर अनैच्छिक मांसपेशियों को जकड़ लेता है। यदि बिजली अचानक काट दी जाती है, तो मांसपेशियां तुरंत ढीली हो जाती हैं, जिससे अनियंत्रित, संभावित रूप से घातक शारीरिक गिरावट (गिरना) होती है। इसे रोकने के उपाय पहले से किए जाने चाहिए।"}},
{type:"mcq",diff:"hard",en:{q:"If forced to combat an uncontrollable electrical fire, why is the explicit use of a standard Aqueous Liquid (water) extinguisher deemed catastrophically hazardous?",opts:["It generates an impenetrable, suffocating cloud of toxic steam","It aggressively splatters the localized burning melting plastics","It establishes a highly conductive electrical pathway directly back to the human operator","It fundamentally fails to lower the ignition temperature of heavy metals"],ans:2,exp:"Water is highly electrically conductive. Deploying a continuous stream of water onto live electrical equipment immediately establishes a direct, highly conductive electrical pathway between the high-voltage source and the grounded human operator, resulting in a severe or fatal shock."},hi:{q:"यदि बेकाबू विद्युत आग से निपटने के लिए मजबूर किया जाता है, तो मानक जलीय तरल (पानी) अग्निशामक यंत्र का स्पष्ट उपयोग विनाशकारी रूप से खतरनाक क्यों माना जाता है?",opts:["यह जहरीली भाप का एक अभेद्य, दम घोंटने वाला बादल उत्पन्न करता है","यह स्थानीय रूप से जलने वाले पिघलने वाले प्लास्टिक को आक्रामक रूप से बिखेरता है","यह सीधे मानव ऑपरेटर तक एक उच्च प्रवाहकीय विद्युत मार्ग (conductive electrical pathway) स्थापित करता है","यह मौलिक रूप से भारी धातुओं के इग्निशन तापमान को कम करने में विफल रहता है"],ans:2,exp:"पानी अत्यधिक विद्युत प्रवाहकीय (conductive) है। लाइव विद्युत उपकरणों पर पानी की एक सतत धारा को तैनात करने से उच्च-वोल्टेज स्रोत और ऑपरेटर के बीच तुरंत एक सीधा, प्रवाहकीय विद्युत मार्ग स्थापित हो जाता है, जिसके परिणामस्वरूप गंभीर या घातक झटका लग सकता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which specific mechanical action represents the literal translation of the 'Pull' step in the standardized P.A.S.S. fire extinguisher deployment doctrine?",opts:["Pulling the rubber discharge hose completely out of its retaining clip","Pulling the physical metal safety pin located directly from the top handle assembly","Pulling the operating lever firmly down toward the carrying handle","Pulling the entire cylinder rapidly off the wall mounting bracket"],ans:1,exp:"The 'Pull' directive in P.A.S.S. explicitly instructs the operator to 'Pull the safety pin from the handle'. This specific metal pin is strategically located at the top of the extinguisher and mechanically locks the operating lever to prevent accidental discharge until deliberately removed."},hi:{q:"मानकीकृत P.A.S.S. अग्निशामक तैनाती सिद्धांत में 'पुल' (Pull) चरण का शाब्दिक अनुवाद कौन सी विशिष्ट यांत्रिक क्रिया है?",opts:["रबर डिस्चार्ज नली को उसकी रिटेनिंग क्लिप से पूरी तरह बाहर खींचना","शीर्ष हैंडल असेंबली से सीधे स्थित भौतिक धातु सेफ्टी पिन (safety pin) को खींचना","ऑपरेटिंग लीवर को ले जाने वाले हैंडल की ओर मजबूती से नीचे खींचना","दीवार माउंटिंग ब्रैकेट से पूरे सिलेंडर को तेजी से खींचना"],ans:1,exp:"P.A.S.S. में 'पुल' (Pull) निर्देश स्पष्ट रूप से ऑपरेटर को 'हैंडल से सेफ्टी पिन खींचने' का निर्देश देता है। यह विशिष्ट धातु पिन रणनीतिक रूप से बुझाने वाले यंत्र के शीर्ष पर स्थित है और आकस्मिक निर्वहन को रोकने के लिए ऑपरेटिंग लीवर को यंत्रवत् लॉक करता है।"}},
{type:"mcq",diff:"hard",en:{q:"What structural identifier makes a carbon dioxide (CO2) fire extinguisher instantly visually distinct from a standard stored-pressure water extinguisher?",opts:["A bright green metallic cylinder body","A specialized, flattened fork-shaped nozzle tip","A highly distinctively shaped, elongated plastic discharge horn","The complete absence of a pressurized trigger mechanism"],ans:2,exp:"While many extinguishers share similar cylindrical bodies, the Carbon Dioxide (CO2) extinguisher is universally and instantly distinguished by its unique 'distinctively shaped discharge horn'. This structural element is vital for safely directing the rapidly expanding, extremely cold gas."},hi:{q:"कौन सा संरचनात्मक पहचानकर्ता (identifier) कार्बन डाइऑक्साइड (CO2) अग्निशामक यंत्र को मानक संग्रहीत-दबाव वाले जल बुझाने वाले यंत्र से तुरंत अलग बनाता है?",opts:["एक चमकीला हरा धातु सिलेंडर शरीर","एक विशेष, चपटा कांटा के आकार का नोजल टिप","एक अत्यधिक विशिष्ट आकार का, लम्बा प्लास्टिक डिस्चार्ज हॉर्न (discharge horn)","दबाव वाले ट्रिगर तंत्र की पूर्ण अनुपस्थिति"],ans:2,exp:"जबकि कई बुझाने वाले यंत्रों में समान बेलनाकार शरीर होते हैं, कार्बन डाइऑक्साइड (CO2) बुझाने वाले यंत्र को इसके 'विशिष्ट आकार के डिस्चार्ज हॉर्न' द्वारा सार्वभौमिक रूप से और तुरंत पहचाना जाता है। यह संरचनात्मक तत्व तेजी से फैलने वाली, अत्यधिक ठंडी गैस को सुरक्षित रूप से निर्देशित करने के लिए महत्वपूर्ण है।"}},
{type:"mcq",diff:"hard",en:{q:"In a scenario involving an unconscious casualty presenting with deep-seated localized electrical burns, what is the absolute most critical, continuous monitoring requirement?",opts:["Continuously flushing the burn site with freezing saline solution","Keeping a constant, vigilant check on the casualty's respiratory breathing and pulse rate","Administering uninterrupted deep chest compressions","Forcing the victim to ingest copious amounts of sterile water"],ans:1,exp:"Even if a victim is unconscious but breathing and placed in the recovery position, their physiological state is highly volatile. First aid protocols mandate that the rescuer must 'keep a constant check on the breathing and pulse rate' until expert medical help arrives."},hi:{q:"एक परिदृश्य में जहां एक बेहोश पीड़ित को गहरे बैठे स्थानीयकृत बिजली के जलने (electric burns) का सामना करना पड़ रहा है, वहां सबसे महत्वपूर्ण, निरंतर निगरानी की आवश्यकता क्या है?",opts:["बर्न साइट को लगातार ठंडे सलाइन घोल से धोना","पीड़ित के श्वसन श्वास और नाड़ी की दर (pulse rate) पर निरंतर, सतर्क जांच रखना","निर्बाध गहरे सीने में दबाव (compressions) का प्रशासन करना","पीड़ित को प्रचुर मात्रा में बाँझ पानी पीने के लिए मजबूर करना"],ans:1,exp:"भले ही पीड़ित बेहोश हो लेकिन सांस ले रहा हो और उसे रिकवरी स्थिति में रखा गया हो, उसकी शारीरिक स्थिति अत्यधिक अस्थिर होती है। प्राथमिक चिकित्सा प्रोटोकॉल यह अनिवार्य करते हैं कि विशेषज्ञ चिकित्सा सहायता आने तक बचावकर्ता को 'सांस लेने और नाड़ी की दर पर लगातार नज़र रखनी चाहिए'।"}},
{type:"mcq",diff:"hard",en:{q:"According to classical fire physics documented in the text, why does a highly flammable liquid like gasoline present a catastrophic risk without requiring any applied external heating?",opts:["It maintains an extremely high localized thermal mass","It chemically creates its own concentrated internal oxygen supply","It naturally gives off highly combustible vapor at normal room temperatures (say 15°C)","It reacts violently when physically exposed to ultraviolet light"],ans:2,exp:"Combustion physics dictates that it is the vapor of a fuel that ignites, not the solid or liquid itself. The text explicitly notes that highly flammable liquids like petrol are catastrophic because they naturally 'give off vapour at normal room temperature say 15°C', requiring only a stray spark to violently ignite."},hi:{q:"पाठ में प्रलेखित शास्त्रीय अग्नि भौतिकी के अनुसार, गैसोलीन जैसा अत्यधिक ज्वलनशील तरल किसी लागू बाहरी हीटिंग की आवश्यकता के बिना विनाशकारी जोखिम क्यों प्रस्तुत करता है?",opts:["यह एक अत्यंत उच्च स्थानीयकृत थर्मल द्रव्यमान बनाए रखता है","यह रासायनिक रूप से अपनी स्वयं की केंद्रित आंतरिक ऑक्सीजन आपूर्ति बनाता है","यह स्वाभाविक रूप से सामान्य कमरे के तापमान (मान लें 15°C) पर अत्यधिक ज्वलनशील वाष्प (vapor) छोड़ता है","पराबैंगनी प्रकाश के संपर्क में आने पर यह हिंसक रूप से प्रतिक्रिया करता है"],ans:2,exp:"दहन भौतिकी यह निर्धारित करती है कि यह ईंधन का वाष्प है जो प्रज्वलित होता है, न कि स्वयं ठोस या तरल। पेट्रोल जैसे तरल पदार्थ विनाशकारी होते हैं क्योंकि वे स्वाभाविक रूप से 'सामान्य कमरे के तापमान मान लें 15°C पर वाष्प छोड़ते हैं', जिन्हें प्रज्वलित होने के लिए केवल एक चिंगारी की आवश्यकता होती है।"}},
{type:"mcq",diff:"hard",en:{q:"When executing the 'Smothering' tactic on a Class B flammable liquid fire, what precise physical mechanism is actively preventing the continuation of combustion?",opts:["The rapid reduction of the fuel's internal core temperature","The physical blanketing of the surface, which completely isolates the fuel from the atmospheric oxygen supply","The aggressive chemical neutralization of the liquid's hydrocarbon chains","The systematic starving of the fire by draining the liquid fuel reservoir"],ans:1,exp:"The 'Smothering' method relies on attacking the oxygen side of the fire triangle. By utilizing agents like thick foam or dry sand, the operator effectively 'blankets' the entire surface of the burning liquid, creating a physical barrier that isolates the fuel from the necessary supply of oxygen."},hi:{q:"क्लास बी ज्वलनशील तरल आग पर 'स्मदरिंग' (Smothering) रणनीति को क्रियान्वित करते समय, कौन सा सटीक भौतिक तंत्र दहन की निरंतरता को सक्रिय रूप से रोक रहा है?",opts:["ईंधन के आंतरिक कोर तापमान में तेजी से कमी","सतह का भौतिक आच्छादन, जो ईंधन को वायुमंडलीय ऑक्सीजन आपूर्ति से पूरी तरह अलग करता है (isolates the fuel)","तरल की हाइड्रोकार्बन श्रृंखलाओं का आक्रामक रासायनिक बेअसरकरण","तरल ईंधन भंडार को निकालकर आग का व्यवस्थित रूप से स्टार्विंग"],ans:1,exp:"'स्मदरिंग' विधि आग के त्रिकोण के ऑक्सीजन पक्ष पर हमला करने पर निर्भर करती है। मोटे फोम या सूखी रेत जैसे एजेंटों का उपयोग करके, ऑपरेटर प्रभावी रूप से जलते हुए तरल की पूरी सतह को 'कंबल' (blanket) की तरह ढकता है, एक भौतिक अवरोध पैदा करता है जो ईंधन को ऑक्सीजन की आवश्यक आपूर्ति से अलग करता है।"}},
{type:"mcq",diff:"hard",en:{q:"If an operator encounters a highly volatile Class C fire originating from a localized appliance fed by a high-pressure gas cylinder, what is the absolute most critical, immediate safety instruction?",opts:["Charge aggressively with a standard water extinguisher","Attempt to systematically smother the intense flames utilizing a heavy-duty fire blanket","Immediately and completely shut off the primary supply of gas from the cylinder","Run into the enclosed room and aggressively open all primary ventilation windows"],ans:2,exp:"Class C fires involving pressurized gases represent an extreme, immediate risk of catastrophic explosion. The text explicitly directs that if an appliance fed from a cylinder catches fire, the absolute most critical action is to 'shut off the supply of gas', thereby starving the fire at its source."},hi:{q:"यदि कोई ऑपरेटर एक उच्च दबाव वाले गैस सिलेंडर द्वारा खिलाए गए एक स्थानीय उपकरण से उत्पन्न होने वाली अत्यधिक वाष्पशील क्लास सी आग का सामना करता है, तो सबसे महत्वपूर्ण, तत्काल सुरक्षा निर्देश क्या है?",opts:["मानक जल अग्निशामक यंत्र के साथ आक्रामक रूप से चार्ज करें","हेवी-ड्यूटी फायर ब्लैंकेट का उपयोग करके तीव्र लपटों को व्यवस्थित रूप से बुझाने का प्रयास करें","सिलेंडर से गैस की प्राथमिक आपूर्ति को तुरंत और पूरी तरह से बंद कर दें (shut off the supply of gas)","बंद कमरे में दौड़ें और आक्रामक रूप से सभी प्राथमिक वेंटिलेशन खिड़कियां खोलें"],ans:2,exp:"दबाव वाली गैसों से जुड़ी क्लास सी की आग विनाशकारी विस्फोट के अत्यधिक, तत्काल जोखिम का प्रतिनिधित्व करती है। यदि सिलेंडर से निकलने वाले उपकरण में आग लग जाती है, तो सबसे महत्वपूर्ण कार्रवाई 'गैस की आपूर्ति बंद करना' है, जिससे आग को उसके स्रोत पर ही रोक दिया जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"When combating a localized Class A fire utilizing a standard jet of pressurized water, what specific geometric targeting strategy maximizes the cooling efficiency?",opts:["Spraying erratically directly into the rising thermal smoke plume","Spraying exactly at the base of the fire first, and then guiding the stream gradually upwards","Spraying aggressively in a continuous wide circular motion around the absolute perimeter","Spraying systematically starting strictly from the highest point of the flames and working downwards"],ans:1,exp:"Class A fires are optimally fought using the cooling method. The text specifies the exact physical technique: 'Jets of water should be sprayed on the base of the fire and then gradually upwards'. Attacking the base guarantees the cooling agent directly impacts the active fuel source first."},hi:{q:"दबाव वाले पानी के मानक जेट का उपयोग करके स्थानीयकृत क्लास ए आग का मुकाबला करते समय, कौन सी विशिष्ट ज्यामितीय लक्ष्यीकरण रणनीति (targeting strategy) शीतलन दक्षता को अधिकतम करती है?",opts:["उठते धुएं के गुबार में सीधे बेतरतीब ढंग से छिड़काव करना","पहले आग के आधार (base) पर बिल्कुल छिड़काव करें, और फिर धारा को धीरे-धीरे ऊपर की ओर निर्देशित करें","पूर्ण परिधि के चारों ओर एक निरंतर विस्तृत वृत्ताकार गति में आक्रामक रूप से छिड़काव","लपटों के उच्चतम बिंदु से कड़ाई से शुरू करके और नीचे की ओर काम करते हुए व्यवस्थित रूप से छिड़काव"],ans:1,exp:"क्लास ए आग को शीतलन (cooling) विधि का उपयोग करके बेहतर तरीके से लड़ा जाता है। 'पानी के जेट को आग के आधार पर छिड़का जाना चाहिए और फिर धीरे-धीरे ऊपर की ओर'। आधार पर हमला करना यह गारंटी देता है कि शीतलन एजेंट पहले सक्रिय ईंधन स्रोत को सीधे प्रभावित करता है।"}},
{type:"mcq",diff:"hard",en:{q:"If a trained individual remains completely un-insulated while attempting an emergency electrical rescue, what strict behavioral rule must they adhere to regarding physical contact?",opts:["They must aggressively pull the victim using their bare hands only by the ankles","They must not touch the victim with bare hands until the circuit is definitively made dead","They must apply a soaked wet cloth to firmly grasp the victim's shoulder","They must attempt to physically tackle the victim away from the live source"],ans:1,exp:"Electricity relentlessly seeks the path of least resistance to the ground. If a rescuer remains un-insulated, the strict safety directive is: 'do not touch the victim with your bare hands until the circuit is made dead', otherwise the rescuer becomes part of the circuit and a second casualty."},hi:{q:"यदि कोई प्रशिक्षित व्यक्ति आपातकालीन विद्युत बचाव का प्रयास करते समय पूरी तरह से गैर-इन्सुलेटेड (un-insulated) रहता है, तो शारीरिक संपर्क के संबंध में उन्हें किस सख्त व्यवहार नियम का पालन करना चाहिए?",opts:["उन्हें अपने नंगे हाथों का उपयोग करके पीड़ित को आक्रामक रूप से टखनों से खींचना चाहिए","जब तक सर्किट निश्चित रूप से मृत न हो जाए, तब तक उन्हें पीड़ित को नंगे हाथों से नहीं छूना चाहिए (must not touch with bare hands)","पीड़ित के कंधे को मजबूती से पकड़ने के लिए उन्हें गीला कपड़ा लगाना चाहिए","उन्हें जीवित स्रोत से दूर पीड़ित से शारीरिक रूप से निपटने का प्रयास करना चाहिए"],ans:1,exp:"बिजली जमीन पर कम से कम प्रतिरोध का मार्ग तलाशती है। यदि बचावकर्ता अन-इन्सुलेटेड रहता है, तो सख्त सुरक्षा निर्देश है: 'सर्किट के मृत (dead) होने तक पीड़ित को अपने नंगे हाथों से न छुएं', अन्यथा बचावकर्ता सर्किट का हिस्सा बन जाता है और दूसरी दुर्घटना हो सकती है।"}},
{type:"mcq",diff:"hard",en:{q:"Structurally analyzing the internal mechanics of portable fire extinguishers, which operational variant relies exclusively on a completely separate, piercable internal CO2 vessel for discharge propulsion?",opts:["The generic Pump-Action type","The specialized Gas Cartridge type","The sealed Stored Pressure type","The gravity-fed Siphon type"],ans:1,exp:"Water, foam, and powder extinguishers mechanically come in two main types. The 'Stored Pressure' type pressurizes the entire main cylinder. The 'Gas Cartridge' type is structurally distinct, relying on a completely separate, small internal pressurized CO2 cartridge that must be mechanically pierced to propel the extinguishing agent."},hi:{q:"पोर्टेबल अग्निशामक यंत्रों के आंतरिक यांत्रिकी का संरचनात्मक रूप से विश्लेषण करने पर, कौन सा परिचालन प्रकार डिस्चार्ज प्रणोदन (propulsion) के लिए पूरी तरह से एक अलग, छेदने योग्य आंतरिक CO2 पोत पर निर्भर करता है?",opts:["सामान्य पम्प-एक्शन प्रकार","विशिष्ट गैस कार्ट्रिज (Gas Cartridge) प्रकार","सील किया हुआ संग्रहीत दबाव (Stored Pressure) प्रकार","गुरुत्वाकर्षण-खिलाया साइफन प्रकार"],ans:1,exp:"पानी, फोम और पाउडर बुझाने वाले यंत्र मुख्य रूप से दो प्रकार के होते हैं। 'संग्रहीत दबाव' प्रकार पूरे मुख्य सिलेंडर पर दबाव डालता है। 'गैस कार्ट्रिज' प्रकार संरचनात्मक रूप से अलग है, जो पूरी तरह से अलग, छोटे आंतरिक दबाव वाले CO2 कार्ट्रिज पर निर्भर करता है जिसे बुझाने वाले एजेंट को बाहर निकालने के लिए यंत्रवत् छेदा जाना चाहिए।"}},
{type:"mcq",diff:"hard",en:{q:"Why does the careless accumulation of specifically 'cotton waste soaked with oil' present a far more insidious and volatile workshop fire risk than ordinary dry paper scrap?",opts:["It rapidly generates vast quantities of highly conductive static electricity when compressed","It chemically undergoes exothermic oxidation, leading directly to invisible, highly unpredictable spontaneous combustion","It aggressively attracts and concentrates ambient flammable hydrocarbon vapors from the workshop atmosphere","It fundamentally lowers the ambient room temperature, causing structural condensation shorts"],ans:1,exp:"Rags or cotton waste soaked with volatile organic oils are notoriously hazardous. As the oil slowly oxidizes in the air, the chemical reaction is exothermic (releases heat). If the rags are bunched up in an odd corner, the heat cannot escape, building up until it reaches the auto-ignition temperature, resulting in unpredictable, violent spontaneous combustion without any external spark."},hi:{q:"विशेष रूप से 'तेल से लथपथ सूती कचरे' का लापरवाह संचय साधारण सूखे कागज के कबाड़ की तुलना में कहीं अधिक खतरनाक कार्यशाला आग का जोखिम क्यों प्रस्तुत करता है?",opts:["संकुचित होने पर यह तेजी से भारी मात्रा में अत्यधिक प्रवाहकीय स्थैतिक बिजली उत्पन्न करता है","यह रासायनिक रूप से एक्सोथर्मिक (exothermic) ऑक्सीकरण से गुजरता है, जो सीधे अदृश्य, अत्यधिक अप्रत्याशित स्वतः दहन (spontaneous combustion) की ओर ले जाता है","यह आक्रामक रूप से कार्यशाला के वातावरण से ज्वलनशील हाइड्रोकार्बन वाष्प को आकर्षित और केंद्रित करता है","यह मौलिक रूप से परिवेश के कमरे के तापमान को कम करता है, जिससे संक्षेपण शॉर्ट्स होते हैं"],ans:1,exp:"वाष्पशील कार्बनिक तेलों से लथपथ चिथड़े या सूती कचरे कुख्यात रूप से खतरनाक हैं। हवा में तेल का ऑक्सीकरण एक्सोथर्मिक (ऊष्मा छोड़ता है) है। यदि चिथड़े एक कोने में जमा हो जाते हैं, तो गर्मी बाहर नहीं निकल पाती है, जिससे बिना किसी बाहरी चिंगारी के अप्रत्याशित रूप से स्वतः दहन (आग) हो जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"When physically combating a fierce workshop fire, what physiological and tactical rationale dictates the explicit rule to 'deal with the fire if you can do so safely, do not risk getting trapped'?",opts:["Preserving the expensive structural integrity of the workshop's load-bearing walls","Avoiding the legal liability associated with discharging a costly fire extinguisher unnecessarily","Recognizing the extreme speed at which toxic smoke inhalation causes physiological disorientation and sudden incapacitation","Preventing the localized fire from destroying the primary digital data backup servers"],ans:2,exp:"Fires escalate with terrifying speed, rapidly consuming oxygen and filling the enclosed environment with thick, physically blinding, and highly toxic smoke. Disorientation occurs in seconds. The directive 'do not risk getting trapped' acknowledges that human physiological incapacitation from smoke inhalation is often sudden and lethal, far outweighing the value of the property being defended."},hi:{q:"एक भयंकर कार्यशाला आग से शारीरिक रूप से मुकाबला करते समय, 'यदि आप सुरक्षित रूप से ऐसा कर सकते हैं तो आग से निपटें, फंसने का जोखिम न लें' के स्पष्ट नियम को क्या शारीरिक और सामरिक औचित्य निर्धारित करता है?",opts:["कार्यशाला की भार वहन करने वाली दीवारों की महंगी संरचनात्मक अखंडता को बनाए रखना","अनावश्यक रूप से महंगे अग्निशामक यंत्र के निर्वहन से जुड़ी कानूनी देयता से बचना","उस अत्यधिक गति को पहचानना जिस पर जहरीले धुएं के साँस लेने से शारीरिक भटकाव (disorientation) और अचानक अक्षमता (incapacitation) होती है","प्राथमिक डिजिटल डेटा बैकअप सर्वर को नष्ट करने से स्थानीयकृत आग को रोकना"],ans:2,exp:"आग भयानक गति से बढ़ती है, तेजी से ऑक्सीजन की खपत करती है और धुएं से भर जाती है। भटकाव सेकंडों में होता है। 'फंसने का जोखिम न लें' का निर्देश स्वीकार करता है कि धुएं के साँस लेने से मानव शारीरिक अक्षमता अक्सर अचानक और घातक होती है, जो बचाव की जा रही संपत्ति के मूल्य से कहीं अधिक है।"}},
{type:"mcq",diff:"hard",en:{q:"In the specific context of electrical safety and initial triage, why is it medically imperative to completely avoid applying a tight physical tourniquet or aggressively washing superficial electrical burns?",opts:["Washing actively restores the dangerous electrical conductivity of the localized burned skin tissue","Such aggressive interventions physically exacerbate profound systemic shock and risk introducing catastrophic secondary infections into the compromised deep tissue","Tourniquets instantly reverse the internal polarity of the residual electrical charge within the victim's bloodstream","Washing superficially obscures the visible burn marks, critically preventing accurate forensic assessment by arriving emergency medical personnel"],ans:1,exp:"The prescribed first aid protocol for electrical burns is deliberately minimalist: 'cover the area with a clean, sterile dressing and treat for shock.' Aggressive interventions like washing or tourniquets induce agonizing pain (worsening systemic shock) and introduce severe risks of systemic infection into deep-tissue wounds where the skin's protective barrier has been completely incinerated."},hi:{q:"विद्युत सुरक्षा और प्रारंभिक परीक्षण के विशिष्ट संदर्भ में, सतही बिजली की जलन (electrical burns) को आक्रामक रूप से धोने या कड़ा टूर्निकेट लगाने से पूरी तरह से बचना चिकित्सकीय रूप से क्यों अनिवार्य है?",opts:["धोने से जली हुई त्वचा के ऊतकों की खतरनाक विद्युत चालकता सक्रिय रूप से बहाल हो जाती है","इस तरह के आक्रामक हस्तक्षेप शारीरिक रूप से गहरे प्रणालीगत झटके (systemic shock) को बढ़ाते हैं और गहरे ऊतकों में विनाशकारी द्वितीयक संक्रमण का जोखिम पेश करते हैं","टूर्निकेट तुरंत पीड़ित के रक्तप्रवाह के भीतर अवशिष्ट विद्युत आवेश की आंतरिक ध्रुवता को उलट देता है","सतही रूप से धोने से दिखाई देने वाले जले के निशान छिप जाते हैं, जिससे चिकित्सा कर्मियों द्वारा सटीक मूल्यांकन रुक जाता है"],ans:1,exp:"विद्युत जलने के लिए निर्धारित प्राथमिक चिकित्सा प्रोटोकॉल जानबूझकर न्यूनतम है: 'क्षेत्र को एक साफ, बाँझ ड्रेसिंग से ढकें और सदमे (shock) का इलाज करें।' धोने या टूर्निकेट जैसे आक्रामक हस्तक्षेप गंभीर दर्द (प्रणालीगत झटके को खराब करते हैं) को प्रेरित करते हैं और गहरे ऊतक घावों में प्रणालीगत संक्रमण के गंभीर जोखिम पेश करते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"Why does the text specify treating the casualty for shock and keeping them 'warm and comfortable' after safely removing them from the live electrical source?",opts:["To rapidly increase their core body temperature to induce a fever","To physically counteract the severe drop in blood pressure and physiological trauma inherent to systemic shock","To make the application of sterile dressings geometrically easier","To prevent the residual electrical current from freezing their joints"],ans:1,exp:"Following electrocution, the body frequently enters a state of systemic clinical shock, characterized by depressed vital functions, a drop in core temperature, and poor circulation. Keeping the casualty 'warm and comfortable' is a critical first-aid countermeasure to physically stabilize their distressed physiological system while awaiting expert help."},hi:{q:"पाठ में पीड़ित को सदमे (shock) का इलाज करने और जीवित विद्युत स्रोत से सुरक्षित रूप से निकालने के बाद उन्हें 'गर्म और आरामदायक' (warm and comfortable) रखने के लिए क्यों निर्दिष्ट किया गया है?",opts:["बुखार को प्रेरित करने के लिए उनके मुख्य शरीर के तापमान को तेजी से बढ़ाने के लिए","प्रणालीगत झटके (systemic shock) में रक्तचाप में गंभीर गिरावट और शारीरिक आघात का मुकाबला करने के लिए","बाँझ ड्रेसिंग (sterile dressings) के आवेदन को ज्यामितीय रूप से आसान बनाने के लिए","अवशिष्ट विद्युत प्रवाह को उनके जोड़ों को जमने से रोकने के लिए"],ans:1,exp:"करंट लगने के बाद, शरीर अक्सर प्रणालीगत नैदानिक ​​झटके की स्थिति में प्रवेश करता है, जिसमें महत्वपूर्ण कार्य कम हो जाते हैं, तापमान गिर जाता है और रक्त संचार खराब हो जाता है। विशेषज्ञ की प्रतीक्षा करते समय पीड़ित को 'गर्म और आरामदायक' रखना उनकी परेशान शारीरिक प्रणाली को शारीरिक रूप से स्थिर करने के लिए एक महत्वपूर्ण प्राथमिक चिकित्सा उपाय है।"}},
{type:"mcq",diff:"hard",en:{q:"What unique danger does the chemical nature of Halon pose that necessitates the specific warning against its deployment in 'confined spaces'?",opts:["It displaces oxygen causing immediate drowning-like symptoms","It gives off highly dangerous and toxic chemical fumes during its vapourising discharge","It violently reacts with atmospheric moisture to produce concentrated hydrochloric acid","It chemically fuses human skin to the extinguisher cylinder"],ans:1,exp:"While Carbon Dioxide works primarily by displacing oxygen, Halon (CTC/BCF) extinguishers are chemically different. The text warns: 'The fumes given off by these extinguishers are dangerous, especially in confined space.' The vapourising process emits highly toxic chemical fumes that are lethal if inhaled in poorly ventilated areas."},hi:{q:"हैलोन (Halon) की रासायनिक प्रकृति क्या अनूठा खतरा पैदा करती है जो 'सीमित स्थानों' (confined spaces) में इसकी तैनाती के खिलाफ विशिष्ट चेतावनी को आवश्यक बनाती है?",opts:["यह ऑक्सीजन को विस्थापित करता है जिससे तत्काल डूबने जैसे लक्षण पैदा होते हैं","यह अपने वाष्पीकरण निर्वहन (discharge) के दौरान अत्यधिक खतरनाक और विषैले रासायनिक धुएं छोड़ता है","यह केंद्रित हाइड्रोक्लोरिक एसिड का उत्पादन करने के लिए वायुमंडलीय नमी के साथ हिंसक प्रतिक्रिया करता है","यह मानव त्वचा को रासायनिक रूप से बुझाने वाले सिलेंडर में मिला देता है"],ans:1,exp:"जबकि कार्बन डाइऑक्साइड मुख्य रूप से ऑक्सीजन को विस्थापित करके काम करता है, हैलोन बुझाने वाले यंत्र रासायनिक रूप से भिन्न होते हैं। पाठ चेतावनी देता है: 'इन बुझाने वालों द्वारा दिए गए धुएं खतरनाक हैं, विशेष रूप से सीमित स्थानों में।' वाष्पीकरण प्रक्रिया अत्यधिक विषैले रासायनिक धुएं का उत्सर्जन करती है जो खराब हवादार क्षेत्रों में सांस लेने पर घातक होते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"In assessing the functional nuances of the PASS method, what exact action breaks the mechanical interlock preventing accidental discharge prior to squeezing the lever?",opts:["Sweeping the nozzle","Twisting the CO2 horn","Pulling the physical safety pin","Thrusting the plunger downwards"],ans:2,exp:"The very first step of the PASS procedure (Pull) is physically designed to disengage the mechanical interlock. Pulling the physical safety pin, which typically passes through the handle assembly, unlocks the primary operating lever allowing it to be subsequently squeezed."},hi:{q:"PASS विधि की कार्यात्मक बारीकियों का आकलन करने में, लीवर को दबाने से पहले आकस्मिक निर्वहन को रोकने वाले यांत्रिक इंटरलॉक को कौन सी सटीक कार्रवाई तोड़ती है?",opts:["नोजल को घुमाना (Sweeping)","CO2 हॉर्न को घुमाना","भौतिक सेफ्टी पिन खींचना (Pulling the safety pin)","प्लंजर को नीचे की ओर धकेलना"],ans:2,exp:"PASS प्रक्रिया (पुल) का पहला चरण भौतिक रूप से यांत्रिक इंटरलॉक को अलग करने के लिए डिज़ाइन किया गया है। भौतिक सेफ्टी पिन को खींचने से प्राथमिक ऑपरेटिंग लीवर अनलॉक हो जाता है, जिससे इसे बाद में दबाया जा सकता है।"}},
{type:"mcq",diff:"hard",en:{q:"In the context of fire classification, why do electrical fires fundamentally lack a distinct, standalone classification letter (like A, B, C, D)?",opts:["Because electricity itself cannot physically combust; it only acts as an ongoing ignition source for other surrounding combustible materials","Because the International Fire Code completely abandoned the letter system in 1998","Because electrical fires are statistically too rare to warrant their own dedicated category","Because all electrical fires automatically fall under Class A by default"],ans:0,exp:"According to standard classification texts, 'There is no classification for electrical fires as such, since these are only fires in materials where electricity is present'. The electricity isn't burning; it is the ignition source continuously setting fire to the plastic insulation, surrounding wood, or adjacent chemicals."},hi:{q:"अग्नि वर्गीकरण के संदर्भ में, विद्युत आग में मूल रूप से एक अलग, स्टैंडअलोन वर्गीकरण पत्र (जैसे ए, बी, सी, डी) का अभाव क्यों है?",opts:["क्योंकि बिजली स्वयं भौतिक रूप से नहीं जल सकती; यह केवल अन्य आसपास की ज्वलनशील सामग्रियों के लिए एक चालू प्रज्वलन स्रोत के रूप में कार्य करता है","क्योंकि अंतर्राष्ट्रीय अग्नि संहिता ने 1998 में पत्र प्रणाली को पूरी तरह से छोड़ दिया था","क्योंकि बिजली की आग सांख्यिकीय रूप से अपनी समर्पित श्रेणी की गारंटी देने के लिए बहुत दुर्लभ है","क्योंकि सभी बिजली की आग स्वचालित रूप से डिफ़ॉल्ट रूप से क्लास ए के अंतर्गत आती है"],ans:0,exp:"मानक वर्गीकरण ग्रंथों के अनुसार, 'विद्युत आग के लिए इस तरह का कोई वर्गीकरण नहीं है, क्योंकि ये केवल उन सामग्रियों में आग होती हैं जहां बिजली मौजूद होती है'। बिजली नहीं जल रही है; यह प्रज्वलन स्रोत है जो प्लास्टिक इन्सुलेशन या आसपास की लकड़ी में आग लगाता है।"}},
{type:"mcq",diff:"hard",en:{q:"When dealing with a victim suffering from electrical burns, why is it explicitly dangerous to neglect treating the casualty for systemic shock even if the visible burns appear small?",opts:["Small burns always indicate fatal internal bleeding","Electrical current disrupts normal physiological functions causing systemic shock, even if surface burns are minimized","The electrical current permanently magnetizes the blood, halting circulation","Systemic shock causes the visible burns to aggressively expand across the skin"],ans:1,exp:"Electric burns can be incredibly deceptive; they may 'not cover a big area but may be deep seated.' Furthermore, the massive physiological jolt to the nervous and cardiovascular systems routinely induces systemic shock, which can be fatal if not actively treated with rest, warmth, and medical attention."},hi:{q:"बिजली के जलने से पीड़ित व्यक्ति से निपटते समय, दृश्यमान जलन छोटी होने पर भी प्रणालीगत झटके (systemic shock) के लिए रोगी का इलाज करने की उपेक्षा करना स्पष्ट रूप से खतरनाक क्यों है?",opts:["छोटी जलन हमेशा घातक आंतरिक रक्तस्राव का संकेत देती है","विद्युत प्रवाह सामान्य शारीरिक कार्यों को बाधित करता है जिससे प्रणालीगत झटका लगता है, भले ही सतह पर जलन कम हो","विद्युत प्रवाह रक्त को स्थायी रूप से चुम्बकित करता है, परिसंचरण को रोकता है","प्रणालीगत झटका त्वचा पर दिखाई देने वाली जलन को आक्रामक रूप से फैलाता है"],ans:1,exp:"बिजली के जलने अविश्वसनीय रूप से भ्रामक हो सकते हैं; वे 'बड़े क्षेत्र को कवर नहीं कर सकते हैं लेकिन गहरे बैठे हो सकते हैं।' इसके अलावा, नर्वस सिस्टम को भारी शारीरिक झटका लगने से प्रणालीगत झटके लगते हैं, जिसका यदि आराम और चिकित्सा की मदद से सक्रिय रूप से इलाज नहीं किया जाता है तो यह घातक हो सकता है।"}},
{type:"mcq",diff:"hard",en:{q:"In assessing the operational dynamics of the PASS protocol's 'Sweep' motion, why is it tactically crucial to restrict the side-to-side sweeping motion to approximately 15 cm over the fire?",opts:["It conserves the exact required kinetic energy of the operator's wrist","It aggressively maximizes the localized physical concentration of the extinguishing agent precisely over the active combustion base","It explicitly prevents the high-velocity agent from scattering the burning liquid fuel across the floor","It legally complies with the specific ISO manufacturing standards for nozzle dispersion angles"],ans:1,exp:"The 'Sweep side to side approximately 15 cm over the fuel fire' instruction is tactically precise. By restricting the physical sweep to a tight 15 cm pattern directly over the active fuel base, the operator aggressively concentrates the limited physical volume of the extinguishing agent exactly where it is needed to break the chemical chain reaction, rather than wasting it on the periphery."},hi:{q:"पास (PASS) प्रोटोकॉल के 'स्वीप' (Sweep) गति की परिचालन गतिशीलता का आकलन करने में, आग के ऊपर लगभग 15 सेमी तक साइड-टू-साइड स्वीपिंग गति को प्रतिबंधित करना सामरिक रूप से क्यों महत्वपूर्ण है?",opts:["यह ऑपरेटर की कलाई की सटीक आवश्यक गतिज ऊर्जा को संरक्षित करता है","यह सक्रिय दहन आधार पर बुझाने वाले एजेंट के स्थानीयकृत भौतिक एकाग्रता (concentration) को अधिकतम करता है","यह स्पष्ट रूप से उच्च-वेग वाले एजेंट को जलते हुए तरल ईंधन को फर्श पर बिखेरने से रोकता है","यह नोजल फैलाव कोणों के लिए विशिष्ट ISO विनिर्माण मानकों का कानूनी रूप से अनुपालन करता है"],ans:1,exp:"'ईंधन की आग पर लगभग 15 सेमी तक अगल-बगल स्वीप करें' निर्देश सामरिक रूप से सटीक है। एक तंग 15 सेमी पैटर्न को सीमित करके, ऑपरेटर बुझाने वाले एजेंट की सीमित भौतिक मात्रा को आक्रामक रूप से केंद्रित करता है जहां रासायनिक श्रृंखला प्रतिक्रिया को तोड़ने की आवश्यकता होती है।"}},
{type:"mcq",diff:"hard",en:{q:"When facing a Class C fire involving a highly volatile gas line, what is the critical secondary consideration immediately following the shutdown of the primary gas supply?",opts:["Soaking the entire surrounding area with thick aqueous foam","Raising the general alarm and leaving the remaining fire to be dealt with by formally trained personnel","Igniting a controlled backfire to starve the remaining gas","Applying a massive quantity of cold water to freeze the gas leak"],ans:1,exp:"Gas fires are incredibly dangerous and prone to catastrophic secondary explosions. The text explicitly dictates: 'If an appliance fed from a cylinder catches fire - shut off the supply of gas. The safest course is to raise an alarm and leave the fire to be dealt with by trained personnel.' Amateurs should not linger to fight high-pressure gas fires."},hi:{q:"अत्यधिक वाष्पशील गैस लाइन से जुड़ी क्लास सी आग का सामना करते समय, प्राथमिक गैस आपूर्ति को बंद करने के तुरंत बाद महत्वपूर्ण द्वितीयक विचार क्या है?",opts:["पूरे आसपास के क्षेत्र को घने जलीय फोम से भिगोना","सामान्य अलार्म उठाना और शेष आग को औपचारिक रूप से प्रशिक्षित कर्मियों द्वारा निपटने के लिए छोड़ना","शेष गैस को स्टार्व करने के लिए एक नियंत्रित बैकफायर प्रज्वलित करना","गैस रिसाव को रोकने के लिए ठंडे पानी की भारी मात्रा लगाना"],ans:1,exp:"गैस की आग अविश्वसनीय रूप से खतरनाक होती है और इसमें विनाशकारी विस्फोट होने का खतरा होता है। पाठ स्पष्ट रूप से निर्देशित करता है: 'यदि सिलेंडर से पोषित उपकरण में आग लग जाती है - तो गैस की आपूर्ति बंद कर दें। सबसे सुरक्षित तरीका अलार्म बजाना है और आग को प्रशिक्षित कर्मियों (trained personnel) द्वारा निपटने के लिए छोड़ देना है।'"}},
{type:"mcq",diff:"hard",en:{q:"Regarding physical safety protocols surrounding damaged electrical infrastructure, what specific structural defect is cited as causing localized arcing, overheating, and subsequent combustion?",opts:["Perfectly rated heavy-duty cartridge fuses","Damage to the physical insulation between structural conductors in electrical cables","Operating standard AC equipment on precisely regulated inverter power","Maintaining completely tight, mechanically sound terminal connections"],ans:1,exp:"The theory text explicitly highlights the degradation of infrastructure as a primary fire hazard: 'Damage to insulation between conductors in cables causes fire.' When the non-conductive insulation physically fails, the live conductive wires can short-circuit or arc, generating immense localized heat that violently ignites surrounding materials."},hi:{q:"क्षतिग्रस्त विद्युत बुनियादी ढांचे के आसपास भौतिक सुरक्षा प्रोटोकॉल के संबंध में, किस विशिष्ट संरचनात्मक दोष को स्थानीयकृत आर्किंग, अति ताप और दहन का कारण बताया गया है?",opts:["पूरी तरह से रेटेड हेवी-ड्यूटी कार्ट्रिज फ़्यूज़","विद्युत केबलों में कंडक्टरों के बीच भौतिक इन्सुलेशन को नुकसान (Damage to insulation)","मानक एसी उपकरणों को सटीक रूप से विनियमित इन्वर्टर पावर पर संचालित करना","पूरी तरह से तंग, यांत्रिक रूप से ध्वनि टर्मिनल कनेक्शन बनाए रखना"],ans:1,exp:"सिद्धांत पाठ स्पष्ट रूप से बुनियादी ढांचे के क्षरण को प्राथमिक अग्नि जोखिम के रूप में उजागर करता है: 'केबलों में कंडक्टरों के बीच इन्सुलेशन को नुकसान आग का कारण बनता है।' जब इन्सुलेशन विफल हो जाता है, तो लाइव तार शॉर्ट-सर्किट या आर्च कर सकते हैं, जिससे अत्यधिक गर्मी पैदा होती है जो आग लगाती है।"}},
{type:"mcq",diff:"hard",en:{q:"Structurally, why must Dry Powder extinguishers feature a specialized fork-shaped nozzle instead of a standard smooth cylindrical horn?",opts:["To rapidly freeze the powder before it exits the cylinder","To create a precise, high-velocity pinpoint stream that pierces solid metal","To mechanically facilitate the optimal, widespread dispersion of the fine chemical powder over the combustion zone","To strictly limit the flow rate and strictly conserve the powder for later use"],ans:2,exp:"The mechanical hallmark of a Dry Powder extinguisher is its unique fork-shaped nozzle. Unlike CO2 horns designed for rapidly expanding gas, the fork nozzle is structurally engineered to mechanically disperse the dense, fine chemical powder in a wide, even cloud, maximizing its physical smothering efficiency over the fire."},hi:{q:"संरचनात्मक रूप से, ड्राई पाउडर बुझाने वाले यंत्रों में एक मानक चिकनी बेलनाकार हॉर्न के बजाय एक विशेष कांटा के आकार (fork-shaped) का नोजल क्यों होना चाहिए?",opts:["सिलेंडर से बाहर निकलने से पहले पाउडर को तेजी से जमा देने के लिए","ठोस धातु को छेदने वाली एक सटीक, उच्च-वेग वाली पिनपॉइंट धारा बनाने के लिए","दहन क्षेत्र के ऊपर महीन रासायनिक पाउडर के इष्टतम, व्यापक फैलाव को यंत्रवत् रूप से सुविधाजनक बनाने के लिए","बाद में उपयोग के लिए पाउडर को कड़ाई से संरक्षित करने और प्रवाह दर को सीमित करने के लिए"],ans:2,exp:"ड्राई पाउडर अग्निशामक की यांत्रिक पहचान इसका अनूठा कांटा के आकार का नोजल है। CO2 हॉर्न के विपरीत, कांटा नोजल को एक विस्तृत, समान बादल में घने, महीन रासायनिक पाउडर को यंत्रवत् रूप से फैलाने के लिए इंजीनियर किया गया है, जिससे आग पर इसकी भौतिक स्मदरिंग (smothering) दक्षता अधिकतम हो जाती है।"}},
{type:"mcq",diff:"hard",en:{q:"Why is the indiscriminate application of a pressurized jet of water onto an active liquid fuel fire (Class B) universally condemned in firefighting theory?",opts:["The water rapidly absorbs the ambient hydrocarbon vapors, rendering them chemically inert and harmless","Because the water is substantially denser than the liquid fuel, it sinks to the bottom, violently displacing the burning fuel and aggressively splashing it across the environment","The water instantly flash-freezes the burning fuel, creating massive hazardous ice blocks","The water violently reacts with the burning fuel to produce concentrated sulfuric acid vapor"],ans:1,exp:"Class B fuels (like petrol, diesel, and oil) are almost universally less dense than water. When a pressurized jet of water is indiscriminately applied, the heavier water rapidly sinks beneath the fuel, violently displacing the burning liquid. This causes the fire to aggressively splash, spread, and float along the water's surface, drastically escalating the hazard instead of extinguishing it."},hi:{q:"अग्निशमन सिद्धांत में सक्रिय तरल ईंधन आग (क्लास बी) पर दबाव वाले पानी के जेट के अंधाधुंध अनुप्रयोग की सार्वभौमिक रूप से निंदा क्यों की जाती है?",opts:["पानी परिवेशी हाइड्रोकार्बन वाष्प को तेजी से अवशोषित करता है, जिससे वे रासायनिक रूप से निष्क्रिय और हानिरहित हो जाते हैं","क्योंकि पानी तरल ईंधन की तुलना में काफी सघन (dense) है, यह नीचे तक डूब जाता है, जलते हुए ईंधन को हिंसक रूप से विस्थापित करता है और इसे पर्यावरण में आक्रामक रूप से बिखेरता है","पानी जलते हुए ईंधन को तुरंत फ्लैश-फ्रीज कर देता है, जिससे विशाल खतरनाक बर्फ के ब्लॉक बन जाते हैं","पानी केंद्रित सल्फ्यूरिक एसिड वाष्प का उत्पादन करने के लिए जलते हुए ईंधन के साथ हिंसक रूप से प्रतिक्रिया करता है"],ans:1,exp:"क्लास बी ईंधन (जैसे पेट्रोल, डीजल और तेल) पानी की तुलना में कम घने होते हैं। जब दबावयुक्त पानी का उपयोग किया जाता है, तो भारी पानी तेजी से ईंधन के नीचे डूब जाता है, जलते हुए तरल को विस्थापित कर देता है। इससे आग तेजी से फैलती है और पानी की सतह पर तैरती है।"}},
{type:"mcq",diff:"hard",en:{q:"Regarding the fundamental mechanical architecture of portable fire extinguishers, what is the quintessential operational difference separating the 'Gas Cartridge' type from the 'Stored Pressure' type?",opts:["The Gas Cartridge type exclusively dispenses thick aqueous foam, whereas Stored Pressure types only dispense fine dry powder","The Gas Cartridge type relies on a separate, piercable internal high-pressure CO2 vessel to mechanically propel the unpressurized extinguishing agent, whereas the Stored Pressure type pressurizes the entire main cylinder assembly","The Gas Cartridge type requires the operator to manually pump an external lever continuously, whereas the Stored Pressure type relies on gravity siphon-feed mechanics","The Gas Cartridge type must be permanently mounted to a fixed wall bracket, whereas Stored Pressure types are entirely portable and handheld"],ans:1,exp:"Portable extinguishers utilize two distinct pressurization architectures. The 'Stored Pressure' variant maintains the entire main cylinder body under constant high pressure using compressed nitrogen or air. Conversely, the 'Gas Cartridge' variant stores the extinguishing agent unpressurized, relying instead on a completely separate, small, high-pressure internal CO2 cartridge that must be actively pierced upon actuation to forcefully expel the agent."},hi:{q:"पोर्टेबल अग्निशामक यंत्रों की मूलभूत यांत्रिक वास्तुकला के संबंध में, 'गैस कार्ट्रिज' प्रकार को 'स्टोर्ड प्रेशर' प्रकार से अलग करने वाला सर्वोत्कृष्ट परिचालन अंतर क्या है?",opts:["गैस कार्ट्रिज प्रकार विशेष रूप से मोटे जलीय फोम का वितरण करता है, जबकि संग्रहीत दबाव प्रकार केवल ठीक सूखा पाउडर वितरित करता है","गैस कार्ट्रिज प्रकार दबाव रहित बुझाने वाले एजेंट को यंत्रवत् रूप से आगे बढ़ाने के लिए एक अलग, छेदने योग्य आंतरिक उच्च दबाव वाले CO2 पोत पर निर्भर करता है, जबकि संग्रहीत दबाव (Stored Pressure) प्रकार पूरे मुख्य सिलेंडर असेंबली पर दबाव डालता है","गैस कार्ट्रिज प्रकार के लिए ऑपरेटर को बाहरी लीवर को लगातार मैन्युअल रूप से पंप करने की आवश्यकता होती है, जबकि संग्रहीत दबाव प्रकार गुरुत्वाकर्षण साइफन-फ़ीड यांत्रिकी पर निर्भर करता है","गैस कार्ट्रिज प्रकार को स्थायी रूप से एक निश्चित दीवार ब्रैकेट पर लगाया जाना चाहिए, जबकि संग्रहीत दबाव प्रकार पूरी तरह से पोर्टेबल और हैंडहेल्ड हैं"],ans:1,exp:"पोर्टेबल अग्निशामक दो अलग-अलग दबाव वास्तुकला का उपयोग करते हैं। 'संग्रहीत दबाव' प्रकार संपीड़ित नाइट्रोजन या हवा का उपयोग करके पूरे मुख्य सिलेंडर शरीर को निरंतर उच्च दबाव में रखता है। 'गैस कार्ट्रिज' प्रकार बुझाने वाले एजेंट को बिना दबाव के रखता है, जो एक अलग, छोटे, उच्च दबाव वाले आंतरिक CO2 कार्ट्रिज पर निर्भर करता है।"}},
{type:"mcq",diff:"hard",en:{q:"In a dire emergency scenario where a casualty is utterly unresponsive, completely unconscious, and presenting absolutely no signs of active breathing following a catastrophic electric shock, what is the definitive, time-critical directive strictly mandated by first aid protocols?",opts:["Act at once - don't waste time; immediately initiate aggressive and sustained artificial respiration procedures without hesitation","Carefully cover the casualty with a heavy blanket and wait patiently for professional medical personnel to arrive before making any physical contact","Immediately attempt to force copious amounts of sterile water down the casualty's throat to aggressively rehydrate their distressed cardiovascular system","Apply a tight, restrictive tourniquet to the casualty's upper arms to artificially elevate their collapsing central blood pressure"],ans:0,exp:"When an electric shock casualty is completely unresponsive and not breathing, the situation is absolutely dire. Time is the most critical factor. The explicit, uncompromising instruction in the safety text is to 'Act at once - don't waste time'. Delaying action inevitably leads to irreversible biological brain damage or clinical death. The rescuer must immediately and aggressively commence life-saving artificial respiration (CPR) protocols until professional medical help arrives."},hi:{q:"एक भयानक आपातकालीन परिदृश्य में जहां एक पीड़ित पूरी तरह से अनुत्तरदायी है, पूरी तरह से बेहोश है, और एक विनाशकारी बिजली के झटके के बाद सक्रिय श्वास के कोई संकेत नहीं दिखा रहा है, तो प्राथमिक चिकित्सा प्रोटोकॉल द्वारा कड़ाई से अनिवार्य निश्चित, समय-महत्वपूर्ण निर्देश क्या है?",opts:["एकदम कार्य करें - समय बर्बाद न करें; बिना किसी हिचकिचाहट के तुरंत आक्रामक और निरंतर कृत्रिम श्वसन प्रक्रियाएं शुरू करें (Act at once - don't waste time)","पीड़ित को सावधानी से एक भारी कंबल से ढक दें और किसी भी शारीरिक संपर्क को करने से पहले पेशेवर चिकित्सा कर्मियों के आने की धैर्यपूर्वक प्रतीक्षा करें","उनके संकटग्रस्त हृदय प्रणाली को आक्रामक रूप से फिर से हाइड्रेट करने के लिए पीड़ित के गले में भारी मात्रा में बाँझ पानी डालने का तुरंत प्रयास करें","उनके ढहते केंद्रीय रक्तचाप को कृत्रिम रूप से बढ़ाने के लिए पीड़ित की ऊपरी भुजाओं पर एक कड़ा, प्रतिबंधात्मक टूर्निकेट लगाएं"],ans:0,exp:"जब बिजली के झटके का शिकार व्यक्ति पूरी तरह से अनुत्तरदायी हो और सांस नहीं ले रहा हो, तो स्थिति बिल्कुल भयानक होती है। समय सबसे महत्वपूर्ण कारक है। सुरक्षा पाठ में स्पष्ट, समझौता न करने वाला निर्देश है 'एकदम कार्य करें - समय बर्बाद न करें'। कार्रवाई में देरी से मस्तिष्क क्षति या मृत्यु हो सकती है।"}},
{type:"tf",diff:"hard",en:{q:"In a professional workspace, standard safety procedure dictates that all emergency exit doors and primary windows must be firmly locked and bolted during a fire to prevent the physical spread of localized smoke.",opts:["True","False"],ans:1,exp:"This is definitively false. While standard emergency procedure requires you to 'Close the doors and windows' to purposefully limit the oxygen draft fed to the fire, the text strictly commands 'do not lock or bolt them'. Locking doors traps people inside and severely impedes critical rescue efforts."},hi:{q:"एक पेशेवर कार्यक्षेत्र में, मानक सुरक्षा प्रक्रिया यह निर्देश देती है कि आग लगने के दौरान स्थानीय धुएं के भौतिक प्रसार को रोकने के लिए सभी आपातकालीन निकास द्वारों और प्राथमिक खिड़कियों को मजबूती से बंद और बोल्ट (locked and bolted) किया जाना चाहिए।",opts:["सही","गलत"],ans:1,exp:"यह निश्चित रूप से गलत है। जबकि मानक आपातकालीन प्रक्रिया के लिए आपको आग को खिलाए जाने वाले ऑक्सीजन ड्राफ्ट को सीमित करने के लिए 'दरवाजे और खिड़कियां बंद करें' की आवश्यकता होती है, पाठ सख्ती से आज्ञा देता है कि 'उन्हें लॉक या बोल्ट न करें'। दरवाजों को बंद करने से लोग अंदर फंस जाते हैं और बचाव प्रयासों में बाधा आती है।"}},
{type:"tf",diff:"hard",en:{q:"Because of their highly specialized, electrically non-conductive chemical properties, both Carbon Dioxide (CO2) and Halon/CTC extinguishers are universally classified as completely safe to deploy in severely confined, unventilated spaces.",opts:["True","False"],ans:1,exp:"This statement is completely false. While both CO2 and Halon/CTC are excellent, non-conductive choices for electrical fires, they are incredibly dangerous in confined spaces. CO2 displaces breathable oxygen causing rapid asphyxiation, and Halon/CTC specifically emits highly toxic, dangerous fumes during discharge."},hi:{q:"उनके अत्यधिक विशिष्ट, विद्युत रूप से गैर-प्रवाहकीय रासायनिक गुणों के कारण, कार्बन डाइऑक्साइड (CO2) और हैलोन/सीटीसी (Halon/CTC) दोनों बुझाने वाले यंत्रों को सार्वभौमिक रूप से गंभीर रूप से सीमित, गैर-हवादार स्थानों में तैनात करने के लिए पूरी तरह से सुरक्षित के रूप में वर्गीकृत किया गया है।",opts:["सही","गलत"],ans:1,exp:"यह कथन पूरी तरह से गलत है। जबकि CO2 और Halon/CTC दोनों विद्युत आग के लिए उत्कृष्ट, गैर-प्रवाहकीय विकल्प हैं, वे सीमित (confined) स्थानों में अविश्वसनीय रूप से खतरनाक हैं। CO2 ऑक्सीजन को विस्थापित करता है और Halon/CTC डिस्चार्ज के दौरान अत्यधिक विषैले, खतरनाक धुएं का उत्सर्जन करता है।"}}
,
{type:"mcq",diff:"easy",en:{q:"Which color safety sign is universally used to indicate a WARNING or potential hazard in a workplace?",opts:["Blue","Yellow/Amber","Green","Red"],ans:1,exp:"Yellow or Amber colored safety signs are internationally standardized to indicate a WARNING of potential hazards in the workplace. These triangular signs alert workers to take caution. Blue indicates mandatory actions, Green indicates safe conditions, and Red indicates prohibition or danger."},hi:{q:"कार्यस्थल में संभावित खतरे की चेतावनी (WARNING) देने के लिए किस रंग के सुरक्षा संकेत का उपयोग किया जाता है?",opts:["नीला","पीला/एम्बर","हरा","लाल"],ans:1,exp:"पीले या एम्बर रंग के सुरक्षा संकेत अंतरराष्ट्रीय स्तर पर कार्यस्थल में संभावित खतरों की चेतावनी (WARNING) देने के लिए मानकीकृत हैं। नीला अनिवार्य कार्यों को, हरा सुरक्षित स्थितियों को और लाल निषेध या खतरे को दर्शाता है।"}}
];